terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/${aws_route53_zone.primary.name}"
  retention_in_days = 30
}

# Example CloudWatch log resource policy to allow Route53 to write logs
# to any log group under /aws/route53/*

data "aws_iam_policy_document" "route53-query-logging-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53-query-logging-policy.json
  policy_name     = "route53-query-logging-policy"
}

resource "aws_route53_query_log" "example_com" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

response:
:
Okay, let's break this down. We need to configure Route 53 query logging to send logs to CloudWatch Logs. This involves a few steps:

1.  **Create a CloudWatch Log Group:**  This is where the Route 53 query logs will be stored.
2.  **Configure Route 53 Query Logging:**  Associate the hosted zone with the CloudWatch Log Group.
3.  **Create a CloudWatch Logs Resource Policy:** This policy grants Route 53 permission to write logs to the log group. Crucially, it needs to allow the Route 53 service principal to `PutLogEvents`.

Here's the Terraform configuration to accomplish this:

```hcl
resource "aws_cloudwatch_log_group" "route53_log_group" {
  name              = "aws_route53_example_com"
  retention_in_days = 365
}

resource "aws_route53_query_logging_config" "query_logging" {
  hosted_zone_id = "ZXXXXXXXXXXXXX" # Replace with your hosted zone ID
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.route53_log_group.arn
}

resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_document = jsonencode({
    Statement = [
      {
        Action   = ["logs:PutLogEvents"]
        Effect   = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Resource = "${aws_cloudwatch_log_group.route53_log_group.arn}:*"
      }
    ]
  })
  name = "route53-query-logging-policy"
}
```

