reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region = "us-east-1" 
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a VPC for internal resources
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/24"
}


# RDS instances
resource "aws_db_instance" "internal" {
  # Internal DB configuration
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier =  "internal"
  username             = "user"
  password             = "password"
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot  = true
}

resource "aws_db_instance" "public" {
  # Public DB configuration
  publicly_accessible  = true
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier = "public"
  username             = "user"
  password             = "password"
  skip_final_snapshot  = true
}

resource "aws_db_subnet_group" "main" {
  name       = "mydb-subnet-group"
  subnet_ids = [aws_subnet.maina.id, aws_subnet.mainb.id]
}

data "aws_availability_zones" "available" {}

# Subnet for RDS
resource "aws_subnet" "maina" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.0/25"
  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "mainb" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.0.128/25"
  availability_zone = data.aws_availability_zones.available.names[1]
}

# Route 53 Public Hosted Zone for external users
resource "aws_route53_zone" "public" {
  name = "example53.com"
}

# Route 53 Private Hosted Zone for internal users
resource "aws_route53_zone" "private" {
  name = "example53.com"
  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# Route 53 Record for Public DB (External Endpoint)
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

# Route 53 Record for Internal DB (Internal Endpoint)
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
}

response:
Okay, let's break this down. We need to create two Route 53 hosted zones – one private and one public.  We'll then need to create records within those zones pointing to RDS endpoints. Since we're not *creating* the RDS instances themselves, we'll assume those exist and have known endpoints (we'll use placeholders). We'll use a DB subnet group for the RDS instances in this configuration. Finally, we'll create A records in both hosted zones pointing to the respective endpoints. For simplicity, I'll assume the Route 53 zones are for the domain `example.com`. You'll likely need to adjust this.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create the private hosted zone
resource "aws_route53_zone" "private_zone" {
  name = "private.example.com"
  vpc = {
    vpc_id = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
    private_zone = true
  }
}

# Create the public hosted zone
resource "aws_route53_zone" "public_zone" {
  name = "public.example.com"
}

# Define the private RDS endpoint (replace with your actual endpoint)
data "aws_rds_cluster" "private_rds" {
  cluster_identifier = "internal-rds-cluster" # Replace with your RDS internal cluster identifier
}

# Define the public RDS endpoint (replace with your actual endpoint)
data "aws_rds_cluster" "public_rds" {
  cluster_identifier = "public-rds-cluster" # Replace with your RDS public cluster identifier
}

# Create A record in the private zone pointing to the private RDS endpoint
resource "aws_route53_record" "private_record" {
  zone_id = aws_route53_zone.private_zone.zone_id
  name    = "internal.example.com"
  type    = "A"
  ttl     = "300"
  records = [data.aws_rds_cluster.private_rds.endpoint]
}

# Create A record in the public zone pointing to the public RDS endpoint
resource "aws_route53_record" "public_record" {
  zone_id = aws_route53_zone.public_zone.zone_id
  name    = "public.example.com"
  type    = "A"
  ttl     = "300"
  records = [data.aws_rds_cluster.public_rds.endpoint]
}

# DB Subnet Group (example - you may already have this created)
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with your subnet IDs
}
```

