  }
}


resource "aws_db_instance" "primary" {
  identifier = "primary"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_1" {
  replicate_source_db  = aws_db_instance.primary.identifier
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-1"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_2" {
  replicate_source_db  = aws_db_instance.primary.identifier
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-2"
  skip_final_snapshot  = true
}


# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_1_cname" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica1.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_1.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 10
  }
  set_identifier = "replica-1-record"
}

resource "aws_route53_record" "replica_2_cname" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica2.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_2.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 20
  }
  set_identifier = "replica-2-record"
}

response:
Okay, let's break this down into steps to create the Terraform configuration.

1.  **Hosted Zone:** We need a Route 53 hosted zone named "main". We'll define this resource first.
2.  **Record Sets:** We will create a record set to manage the DNS records. This will be the core of the weighted routing.
3.  **Primary Instance Record:** A record for the primary DB instance ("primary").
4.  **Replica Instance Records:** Records for the replica DB instances ("replica-1" and "replica-2").
5.  **Weighted Routing:** Configure the record set to use weighted routing, assigning weights to each of the DB instance records.

Here's the Terraform configuration that implements this:

```hcl
resource "aws_route53_zone" "main" {
  name = "main"
}

resource "aws_route53_record" "weighted_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary" # The DNS name for this record, e.g., primary.example.com if your hosted zone is example.com
  type    = "A"
  ttl     = "60"
  records = [] # Will be populated by routing policy

  routing_policy {
    type = "WEIGHTED"
  }
}

resource "aws_route53_record" "primary_instance" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary"
  type    = "A"
  ttl     = "60"
  records = ["192.0.2.1"] # Replace with the actual IP address of the primary DB instance

  routing_policy {
    type = "WEIGHTED"
    weight = 50 # 50% of traffic
  }
}

resource "aws_route53_record" "replica_instance_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-1"
  type    = "A"
  ttl     = "60"
  records = ["192.0.2.2"] # Replace with the actual IP address of replica-1.

  routing_policy {
    type = "WEIGHTED"
    weight = 25 # 25% of traffic
  }
}

resource "aws_route53_record" "replica_instance_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-2"
  type    = "A"
  ttl     = "60"
  records = ["192.0.2.3"] # Replace with the actual IP address of replica-2

  routing_policy {
    type = "WEIGHTED"
    weight = 25 # 25% of traffic
  }
}
```

