  name = "eb_ec2_profile"
  roles = [aws_iam_role.eb_ec2_role.name]
}

resource "aws_elasticbeanstalk_application" "my_api_app" {
  name = "my_api_app"
}

resource "aws_elasticbeanstalk_environment" "example" {
  name            = "my-eb-env" # Added a specific environment name
  application     = aws_elasticbeanstalk_application.my_api_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.5.6 running Node.js 18" # Choose a suitable stack
  option_settings = [
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "MeasureName"
      option_value = "CPUUtilization"
    },
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "Statistic"
      option_value = "Average"
    },
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "Unit"
      option_value = "Percent"
    },
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "Period"
      option_value = "60"
    },
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "EvaluationPeriods"
      option_value = "5"
    },
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "LowerThreshold"
      option_value = "70"
    },
    {
      namespace = "aws:autoscaling:trigger"
      option_name = "UpperThreshold"
      option_value = "90"
    },
    {
      namespace = "aws:elasticbeanstalk:environment"
      option_name = "EnvironmentType"
      option_value = "LoadBalanced"  # Ensures Auto Scaling is used
    },
  ]
  instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
}
