  name               = "eb-ec2-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
  tags = {
    Name = "Elastic Beanstalk EC2 Role"
  }
}

# Create an IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb-ec2-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create an Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "myapp" {
  name = "myapp"
}

# Create an Elastic Beanstalk Application Version
resource "aws_elasticbeanstalk_application_version" "version" {
  name         = "version"
  application_name = aws_elasticbeanstalk_application.myapp.name
  source_bundle {
    s3_bucket = aws_s3_bucket.example.bucket
    s3_key    = "examplebucket_object"
  }

  tags = {
    Version = "v1"
  }
}

# Create an Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "eb_env" {
  name              = "eb-env"
  application_name  = aws_elasticbeanstalk_application.myapp.name
  version_label     = aws_elasticbeanstalk_application_version.version.version
  environment_type  = "SingleInstance" # Or "LoadBalanced" or other type
  solution_stack_name = "64bit Amazon Linux 2 v3.5.4 running Node.js 18" # Choose appropriate stack

  settings = [
    {
      namespace = "aws:elasticbeanstalk:environment"
      option_name = "EnvironmentType"
      option_value = "SingleInstance"
    },
    {
      namespace = "aws:elasticbeanstalk:environment:process"
      option_name = "HealthCheckPath"
      option_value = "/"
    },
  ]

  instance_profile_name = aws_iam_instance_profile.eb_ec2_profile.name
}

# Create Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"  # Replace with your domain name
}

# Get the environment's CNAME
data "aws_elasticbeanstalk_environment" "current_env" {
  environment_name = aws_elasticbeanstalk_environment.eb_env.name
}

# Create a Route 53 Record
resource "aws_route53_record" "record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"  # Replace with your desired subdomain
  type    = "CNAME"
  ttl     = "300"
  records = [data.aws_elasticbeanstalk_environment.current_env.cname]
}
