Okay, let's break this down into steps to create the Terraform configuration for a Blue-Green deployment with Route 53 weighted routing to Elastic Beanstalk environments.

1.  **Data Sources:** We need data sources to fetch the Elastic Beanstalk environment URLs (both "blue" and "green"). This assumes the environments already exist.
2.  **Route 53 Zone:** We need the Hosted Zone ID of the DNS zone where we'll be creating the records. This is an input variable because it's environment-specific.
3.  **Route 53 Records:** We'll create two Route 53 `A` records, one for "blue" and one for "green".  These will point to the Elastic Beanstalk environment URLs we retrieved using the data sources. The records will use a weighted routing policy.
4.  **Variables:** We'll define variables for the Hosted Zone ID, the weights for the blue and green environments, and the DNS name.
5.  **Outputs:** Display DNS record names for ease of access.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "hosted_zone_id" {
  type        = string
  description = "The ID of the Route 53 Hosted Zone"
}

variable "dns_name" {
  type        = string
  description = "The DNS name for the Blue/Green environment (e.g., app.example.com)"
}

variable "blue_weight" {
  type        = number
  description = "Weight for the blue environment (e.g., 80)"
  default     = 80
}

variable "green_weight" {
  type        = number
  description = "Weight for the green environment (e.g., 20)"
  default     = 20
}

data "aws_elasticbeanstalk_environment" "blue" {
  application_name = "your-application-name" # Replace with your application name
  environment_name = "blue"
}

data "aws_elasticbeanstalk_environment" "green" {
  application_name = "your-application-name" # Replace with your application name
  environment_name = "green"
}

resource "aws_route53_record" "blue" {
  zone_id = var.hosted_zone_id
  name    = var.dns_name
  type    = "A"
  set_identifier = "blue"

  weighted_routing_policy {
    weight = var.blue_weight
  }

  records = [data.aws_elasticbeanstalk_environment.blue.endpoint_url]
}

resource "aws_route53_record" "green" {
  zone_id = var.hosted_zone_id
  name    = var.dns_name
  type    = "A"
  set_identifier = "green"

  weighted_routing_policy {
    weight = var.green_weight
  }

  records = [data.aws_elasticbeanstalk_environment.green.endpoint_url]
}

output "blue_record_name" {
  value = aws_route53_record.blue.name
}

output "green_record_name" {
  value = aws_route53_record.green.name
}
```

