terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}
# RDS Database Configuration
resource "aws_db_instance" "my_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "mydbuser"
  password             = "mypassword"
  parameter_group_name = "default.mysql5.7"
  multi_az             = true
  skip_final_snapshot  = true
  backup_retention_period = 7  # Enable backups with 7-day retention
  apply_immediately       = true
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-app"
  description = "My Application"
}

# Original Elastic Beanstalk Environment (Blue)
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "my-app-blue-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASS"
    value     = aws_db_instance.my_db.password
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# New Elastic Beanstalk Environment (Green), for the new version
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "my-app-green-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASS"
    value     = aws_db_instance.my_db.password
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
    }
}

# Taking a snapshot before deployment
resource "aws_db_snapshot" "my_db_snapshot" {
  db_instance_identifier = aws_db_instance.my_db.identifier
  db_snapshot_identifier = "my-db-snapshot-${formatdate("YYYYMMDDHHmmss", timestamp())}"
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}

# Weighted DNS records for Blue and Green environments
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 120
  }
  set_identifier = "BlueEnvironment"
  records = [
    aws_elastic_beanstalk_environment.blue_env.cname
  ]
}

resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 60
  }
  set_identifier = "GreenEnvironment"
  records = [
    aws_elastic_beanstalk_environment.green_env.cname
  ]
}

response:
:
Okay, let's break this down. We need to create a blue/green deployment pipeline with Elastic Beanstalk, backed by an RDS database. Here's the plan:

1.  **RDS Instance:** Create an RDS instance (MySQL in this example; can be altered).
2.  **Database Snapshot:** Create a snapshot of the RDS instance *before* the Beanstalk environment is updated.
3.  **Elastic Beanstalk Application:** Set up an Elastic Beanstalk application.
4.  **Blue Environment:** Create the initial "blue" Elastic Beanstalk environment.
5.  **Green Environment:** Create a second "green" Elastic Beanstalk environment. We'll switch traffic to this later, representing the deployment.
6.  **Instance Profile:** Configure the Elastic Beanstalk environments to use the specified instance profile.
7.  **Database Credentials:**  We'll need to securely pass the database credentials to the Elastic Beanstalk environments. This will be done using environment variables.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# --- RDS Instance ---
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  name                 = "mydb"
  password             = "your_db_password" # Replace with a secure password
  username             = "admin"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  tags = {
    Name = "mydb"
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "mydb-subnet-group"
  subnet_ids = [
    "subnet-xxxxxxxxxxxxx", # Replace with your subnet IDs
    "subnet-yyyyyyyyyyyyy"  # Replace with your subnet IDs
  ]

  tags = {
    Name = "mydb-subnet-group"
  }
}

resource "aws_security_group" "rds" {
  name        = "rds-sg"
  description = "Allow inbound traffic to RDS"
  vpc_id      = "vpc-xxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #WARNING: Do not use 0.0.0.0/0 in production, restrict to your EB environment's security group, or specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# --- Database Snapshot ---
resource "aws_db_snapshot" "pre_deploy_snapshot" {
  db_instance_identifier = aws_db_instance.default.id
  depends_on = [aws_db_instance.default] # Ensure DB is created first
}

# --- Elastic Beanstalk Application ---
resource "aws_elasticbeanstalk_application" "app" {
  name = "my-eb-app"

  tags = {
    Name = "my-eb-app"
  }
}

# --- Blue Environment ---
resource "aws_elasticbeanstalk_environment" "blue" {
  name             = "my-eb-blue"
  application_name = aws_elasticbeanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Node.js 18" #Change this to your solution stack
  instance_profile_name = "ec2_eb_profile1"

  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_USER"
    option_value = aws_db_instance.default.username
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_PASSWORD"
    option_value = aws_db_instance.default.password
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_HOST"
    option_value = aws_db_instance.default.address
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_NAME"
    option_value = "my_db"
  }
}

# --- Green Environment ---
resource "aws_elasticbeanstalk_environment" "green" {
  name             = "my-eb-green"
  application_name = aws_elasticbeanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Node.js 18" #Change this to your solution stack
  instance_profile_name = "ec2_eb_profile1"

  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_USER"
    option_value = aws_db_instance.default.username
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_PASSWORD"
    option_value = aws_db_instance.default.password
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_HOST"
    option_value = aws_db_instance.default.address
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:application:environment"
    option_name = "DB_NAME"
    option_value = "my_db"
  }
}
```

Key improvements and explanations:

*   **RDS Resource:**  Creates the RDS instance.  I've used MySQL as an example.  Adapt the `engine` and `engine_version` as needed. Pay close attention to the `db_subnet_group_name` and `vpc_security_group_ids`, replacing the placeholders with your actual values.
*   **DB Snapshot:** Triggers the snapshot *after* the RDS instance is created using `depends_on`.
*   **Elastic Beanstalk Resources:** Defines the Elastic Beanstalk application and two environments (blue and green).
*   **Option Settings:**  Crucially, it includes `option_settings` to configure the database connection details within your Elastic Beanstalk environment.  I'm passing `DB_USER`, `DB_PASSWORD`, `DB_HOST`, and `DB_NAME` as environment variables.  *Never hardcode credentials like this in production; use a secure parameter store like AWS Systems Manager Parameter Store or Secrets Manager and retrieve them here.*
*   **Instance Profile:** It sets the `instance_profile_name` for both environments to `ec2_eb_profile1`, as requested.  Make sure this profile exists and has the necessary permissions (e.g., access to RDS).
*   **Error Handling:** The `depends_on` attributes is essential to guarantee correct resource creation order.
*   **Security:**  The RDS security group configuration allows traffic from `0.0.0.0/0` which is very insecure for production. *Always* restrict this to your EB environment's security group or specific authorized IP addresses.
*   **Solution Stack**: Added a solution stack. Must be adjusted to suit the actual application’s needs.

**Important considerations for a complete blue/green deployment:**

*   **Traffic Switching:** This configuration *creates* the environments. You'd need an additional mechanism (e.g., Route 53 weighted records, Elastic Load Balancer listeners) to *switch* traffic from the blue to the green environment.
*   **Health Checks:** Configure health checks in Elastic Beanstalk to ensure the green environment is healthy *before* switching traffic.
*   **Automated Rollback:**  Implement automated rollback in case the green deployment fails.
*   **Secure Secrets Management:**  Replace the hardcoded database password with a secure method of storing and retrieving credentials (AWS Secrets Manager, Systems Manager Parameter Store).
*   **Monitoring and Alerting:**  Monitor both environments closely during the deployment and set up alerts to notify you of any issues.
*   **Versioning:** Use version control for your Terraform code and implement a CI/CD pipeline to automate deployments.
*   **Subnet IDs & VPC ID** Replace placeholder values with your actual IDs.

Remember to replace the placeholder values (region, database password, subnet IDs, VPC ID) with your actual values before running this configuration. Also, adapt the solution stack to your application.

