reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# RDS database instance
resource "aws_db_instance" "my_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql" 
  engine_version       = "8.0" 
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "dbpassword" 
  parameter_group_name = "default.mysql8.0"
  multi_az             = true 
  apply_immediately    = true 
  skip_final_snapshot  = true
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-application"
  description = "My Auto-Scaling Application"
}

# Elastic Beanstalk Environment with Auto-Scaling
resource "aws_elastic_beanstalk_environment" "my_app_env" {
  name                = "my-application-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.small" 
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1" 
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "4"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name = "MeasureName"
    value = "CPUUtilization"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name = "Unit"
    value = "Percent"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerThreshold"
    value     = "20"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperThreshold"
    value     = "60"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASSWORD"
    value     = aws_db_instance.my_db.password
  }
}

response:
Okay, let's break this down into steps to generate the Terraform configuration:

1. **Provider Configuration:** We'll need to configure the AWS provider. This involves specifying the region.
2. **RDS Instance:**  Create an RDS instance. We'll need to define its engine (let's assume MySQL for simplicity), instance class, allocated storage, DB name, username, and password.  A security group will be created to permit access.
3. **Elastic Beanstalk Application and Environment:** This is the core. We'll create an Elastic Beanstalk application and an environment within it. This includes specifying the solution stack (e.g. 64bit Amazon Linux 2 v3.0 with Docker), environment name, instance type, and the key configuration point of attaching it to the RDS instance.
4. **Elastic Beanstalk scaling Configuration**: We will set up autoscaling based on CPU utilization, using CloudWatch alarm.
5. **IAM Role:** The configuration will make use of an existing IAM role to grant Elastic Beanstalk access to AWS resources.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

resource "aws_db_instance" "default" {
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  name                 = "my_db1"
  password             = "your_db_password" # Replace with a strong password
  username             = "admin"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  skip_final_snapshot = true
}

resource "aws_db_subnet_group" "default" {
  name       = "my-db-subnet-group"
  subnet_ids = [
    "subnet-0bb1c79de3EXAMPLE", # Replace with your subnet IDs
    "subnet-06b66928a8EXAMPLE"  # Replace with another subnet ID
  ]
}

resource "aws_security_group" "rds" {
  name        = "rds-security-group"
  description = "Allow inbound traffic to RDS"
  vpc_id      = "vpc-0abcdef1234567890" # Replace with your VPC ID

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Consider restricting this to your application's VPC CIDR
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}



resource "aws_elastic_beanstalk_application" "default" {
  name = "my-eb-app"
}

resource "aws_elastic_beanstalk_environment" "default" {
  application_name = aws_elastic_beanstalk_application.default.name
  environment_name = "my-eb-env"
  solution_stack_name = "64bit Amazon Linux 2 v3.0 with Docker"
  instance_type = "t2.micro"

  settings = [
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      option_name = "DATABASE_URL"
      option_value = "mysql://${aws_db_instance.default.username}:${aws_db_instance.default.password}@${aws_db_instance.default.address}:${aws_db_instance.default.port}/my_db1"
    },
    {
      namespace = "aws:elasticbeanstalk:environment:process"
      option_name = "HealthCheckPath"
      option_value = "/"
    }
  ]

  tags = {
    Name = "My Elastic Beanstalk Environment"
  }
}

resource "aws_autoscaling_metric_alarm" "cpu_utilization" {
  alarm_name          = "CPUUtilizationHigh"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 300
  statistic           = "Average"
  threshold           = 70
  alarm_description   = "Alarm when CPU utilization exceeds 70%"

  dimensions = {
    InstanceId = "i-xxxxxxxxxxxxx" # Replace with a sample instance ID from the Beanstalk environment. You may need to fetch it dynamically.
  }

  alarm_actions = [
    # Replace with an autoscaling action like sending a notification or adjusting scaling policy
  ]
}

resource "aws_iam_instance_profile" "eb_profile" {
  name = "eb_ec2_profile"
  role_name = "YourElasticBeanstalkRole" # Replace with existing IAM role name
}

```

**Important Considerations:**

*   **Replace Placeholders:**  The code contains several placeholders (e.g., region, database password, subnet IDs, VPC ID, instance ID, IAM role name) that *must* be replaced with your actual values.
*   **Security:** The `cidr_blocks = ["0.0.0.0/0"]` for the RDS security group is insecure.  Restrict it to the CIDR block(s) of your application's VPC or to specific trusted IP addresses.
*   **Instance ID:** The `InstanceId` in `aws_autoscaling_metric_alarm` needs to be a valid instance ID from your Elastic Beanstalk environment.  You will likely need to use Terraform `data` sources or output values from the Elastic Beanstalk environment resource to fetch this dynamically.
*   **IAM Role:** Ensure that the IAM role you specify (`YourElasticBeanstalkRole`) has the necessary permissions for Elastic Beanstalk to manage resources like EC2 instances, Auto Scaling groups, and access RDS.
*   **Database Configuration:** Adjust the RDS instance class, storage, and parameters according to your application’s needs.
*   **Error Handling**: This configuration doesn't include detailed error handling or checks. For production use, add more robust error handling mechanisms.
*   **Autoscaling Configuration**: The `alarm_actions` are left empty; you need to replace them with appropriate actions, such as sending notifications to SNS or triggering autoscaling policy changes.
*   **Dependencies:**  Ensure the required IAM roles and VPC resources exist prior to running this configuration.

This complete configuration provides a starting point for deploying an Elastic Beanstalk environment with an RDS database and autoscaling. Be sure to carefully review and customize it to fit your specific requirements and security best practices.

