  provider = aws.us_east_1
  name = "myapp.com"
}

# Latency Based Routing in Route 53 for US East Elastic Beanstalk Environment
resource "aws_route53_record" "eb_env_us_east" {
  provider = aws.us_east_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  set_identifier = "EastEnv"
  latency_routing_policy {
    region = "us-east-1"
  }
}

resource "aws_route53_record" "eb_env_eu_west" {
  provider = aws.eu_west_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  set_identifier = "WestEnv"
  latency_routing_policy {
    region = "eu-west-1"
  }
}

response:
Okay, let's break this down into a Terraform configuration. Here's the plan:

1.  **Provider Configuration:** Configure AWS providers for both `us-east-1` and `eu-west-1`.
2.  **RDS Databases:** Create RDS instances in each region.
3.  **Elastic Beanstalk Applications & Environments:** Create Elastic Beanstalk applications and environments (using the given names) in both regions. Attach the RDS databases created in step 2 to these environments.  We'll assume fairly minimal EB configurations for simplicity, focusing on the core setup. Importantly, the EB environments must have appropriate IAM roles for DB access. We'll utilize an existing instance profile.
4.  **Route 53 Hosted Zone:** Create a Route 53 hosted zone for the domain.
5.  **Route 53 Records:** Create Route 53 A records (aliases) that point to the Elastic Beanstalk environments in each region.  We'll use weighted routing to distribute traffic.

Here's the Terraform code:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Variables - For easier customization
variable "domain_name" {
  type        = string
  default     = "example.com"  # Replace with your domain
  description = "The domain name for Route 53"
}

variable "eb_instance_profile" {
  type        = string
  default     = "eb_ec2_profile3"
  description = "The name of the EC2 instance profile for Elastic Beanstalk"
}

# Configure the us-east-1 region
provider "aws" {
  alias  = "us-east-1"
