Okay, let's break down this request into steps to build the Terraform configuration for an AWS CodeBuild project with a sample IAM role and GitHub source.

1.  **IAM Role:** CodeBuild needs permissions to access other AWS resources and to pull code from the source repository. We'll create a basic IAM role with necessary permissions. This includes permissions for CodeBuild, CloudWatch Logs, and S3 access (in case build outputs need to be stored in S3).
2.  **CodeBuild Project:**  We'll define a `aws_codebuild_project` resource.  Key attributes include:
    *   `name`: A unique name for the project.
    *   `description`: A brief description.
    *   `source`: Specifies the GitHub repository (including branch).
    *   `environment`: Defines the OS image, compute type, and privileged mode.
    *   `artifacts`: Specify the type of build output (e.g., S3) and name.
    *   `service_role_arn`: The ARN of the IAM role created in step 1.
3.  **GitHub Connection:** If a GitHub connection is not already present, it must first be created. For simplicity, this configuration doesn't explicitly create a GitHub connection but assumes one exists or can be created separately and its ARN is available.
4.  **Output:**  We'll output the CodeBuild project name for easy reference.

```hcl
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild-policy"
  description = "Policy for CodeBuild"
  policy      = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Action = [
          "s3:*"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:s3:::*" # Replace with a specific bucket ARN for best practice
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "example_project" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project using GitHub source"
  source {
    type      = "GITHUB"
    location  = "https://github.com/terraform-aws-modules/terraform-aws-modules" # replace with your repo
    branch    = "master" # replace with your branch
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX"
    privileged_mode              = false
  }

  artifacts {
    type = "NO_ARTIFACTS"  # Could be S3 if needed
  }

  service_role_arn = aws_iam_role.codebuild_role.arn

  tags = {
    Name = "Example CodeBuild"
  }
}

output "codebuild_project_name" {
  value = aws_codebuild_project.example_project.name
}
