1.  **An IAM Role:** CodeBuild needs permissions to access other AWS services (like S3 for source code, ECR for images, etc.). We'll define a sample IAM role with basic CodeBuild permissions.  This role will be assumed by CodeBuild's service.
2.  **CodeBuild Project:** This is the core resource.  We'll configure its source, environment (image, compute type, privilege mode), and buildspec.
3.  **Build Batch Configuration:** We'll need a build batch to control how builds are executed.

Here's a Terraform configuration that addresses these requirements:

```hcl
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild-policy"
  description = "Policy for CodeBuild to access S3 and ECR"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
        ],
        Effect   = "Allow",
        Resource = "*"
      },
      {
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage",
          "ecr:DescribeRepositories",
        ],
        Effect = "Allow",
        Resource = "*"
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}


resource "aws_codebuild_project" "example" {
  name         = "example-project"
  description  = "An example CodeBuild project"

