terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lex_intent" "order_flowers" {
  name = "OrderFlowers"
  description = "Intent to order a bouquet of flowers for pick up"

  sample_utterances = [
    "I would like to pick up flowers",
    "I would like to order some flowers",
  ]

  slot {
    name                     = "FlowerType"
    description              = "Type of flower to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1

    sample_utterances = ["I would like to get {FlowerType} flower."]

    value_elicitation_prompt {
      message {
        content             = "What type of flower would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PickupDate"
    description              = "Date of flower pickup"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.DATE"
    priority                 = 2

    value_elicitation_prompt {
      message {
        content             = "When would you like to pickup your flower?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, your {FlowerType} will be ready for pickup on {PickupDate}.  Does this sound okay?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  rejection_statement {
    message {
      content      = "Okay, I will not place your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "order_flowers" {
  name     = "OrderFlowers"
  description = "Bot to order flowers on the behalf of a user"
  locale   = "en-US"
  process_behavior = "BUILD"
  voice_id = "Salli"
  child_directed = false
  create_version = false
  detect_sentiment            = false
  idle_session_ttl_in_seconds = 600

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_flowers.name
    intent_version = aws_lex_intent.order_flowers.version
  }
}

response:
: Okay, let's break down the creation of an AWS Lex chatbot with Terraform. Here's a logical progression of steps and the corresponding Terraform resources we'll need:

1.  **IAM Role:** Lex needs permissions to interact with other AWS services. We'll create an IAM role with the necessary policies.
2.  **Lex Bot:** The core Lex bot resource. We'll define its name, idle session timeout, voice/text interaction mechanisms and potentially enable logging.
3.  **Lex Intent:**  Defines what the user wants to achieve (e.g., "Order a pizza"). This includes sample utterances, slots, and fulfillment configuration. We'll need to create at least one intent.
4. **Lex Slot Type:** Defines the data types that can be captured from user input (e.g., pizza size, toppings). This is also necessary for defining the intents.

Here's the Terraform configuration in HCL format, aiming for a minimal, functional example with one intent and a simple slot type:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create an IAM role for Lex
resource "aws_iam_role" "lex_role" {
  name               = "lex-chatbot-role"
  description        = "IAM role for AWS Lex chatbot"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lex.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })
}

# Attach necessary policies to the IAM role
resource "aws_iam_policy_attachment" "lex_policy_attachment" {
  name       = "lex-policy-attachment"
  roles      = [aws_iam_role.lex_role.name]
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly" # Least privilege - only allows running bots
}

# Create a Lex Bot
resource "aws_lex_bot" "lex_bot" {
  name          = "OrderPizzaBot"
  idle_session_timeout_in_minutes = 5
  child_directed           = false
  logging = true
  role_arn = aws_iam_role.lex_role.arn
}

# Create a Lex Slot Type
resource "aws_lex_slot_type" "pizza_size_slot" {
  name        = "PizzaSize"
  description = "Defines the size of a pizza"
  enumeration_values = [
    "Small",
    "Medium",
    "Large",
  ]
  value_selection_setting {
    resolution_strategy = "TOP_RESOLUTION"
  }
}

# Create a Lex Intent
resource "aws_lex_intent" "order_pizza_intent" {
  name              = "OrderPizza"
  description       = "Intent to order a pizza"
  fulfillment_activity {
    type = "CodeHook"
    settings {
      code_hook_arn = "" # Replace with your Lambda function ARN
      message_version = "1.0"
    }
  }
  conclusion_statement {
    response_card {
      version = 1
      content = "Your pizza has been ordered!"
    }
  }
  sample_utterances = [
    "I want to order a pizza",
    "Order me a pizza",
    "Can I get a pizza",
  ]

  slot {
    name        = "PizzaSize"
    slot_constraint = "Required"
    slot_type_name  = aws_lex_slot_type.pizza_size_slot.name
    value_elicitation_setting {
      prompt_specification {
        max_attempts = 2
        message {
          content_type = "PlainText"
          content      = "What size pizza would you like?"
        }
        response_card {
          version = 1
          content = "Choose your pizza size."
        }
      }
    }

  }
}
```

