  name = "OrderPizzaIntent"
  create_version = true

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name = "PizzaType"
    description = "Type of pizza to order"
    priority = 1  # must be in [1, 100]
    slot_type = aws_lex_slot_type.PizzaType.name
    slot_type_version = aws_lex_slot_type.PizzaType.version
    slot_constraint = "Required"

    sample_utterances = ["I want a {PizzaType} pizza.", "A {PizzaType} pizza please."]

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content = "What type of pizza would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content = "So, you would like to order a pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
        content = "Sorry, I don't know how to help then"
        content_type = "PlainText"
      }
    }

  follow_up_prompt {
    prompt {
      max_attempts = 2
      message {
        content = "Would you like anything else with your order?"
        content_type = "PlainText"
      }
    }
    rejection_statement {
      message {
        content = "OK, Your pizza is on its way."
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_slot_type" "PizzaType" {
  create_version = true
  description = "Types of pizza available to order"
  name = "PizzaTypes"
  enumeration_value {
    value = "Margherita"
  }
  enumeration_value {
    value = "Pepperoni"
  }
}

response:
 Okay, let's break down the creation of an AWS Lex bot for pizza ordering with a follow-up prompt.

1.  **Core Resources:** We'll need an `aws_lex_bot`, `aws_lex_intent`, `aws_lex_slot_type`, `aws_lex_slot`, and `aws_lex_bot_alias`. We'll also need `aws_lex_intent_confirmation_prompt` and potentially `aws_lex_intent_fulfillment_activity`.

2.  **Bot Structure:** The intent will be `OrderPizza`. We'll have slots for pizza type and quantity. We'll use a confirmation prompt to verify the order details.

3. **Prompt structure:** We'll define a confirmation prompt that repeats the order to the user. The follow-up prompt asks for delivery address.

4.  **Sample Utterances:** We will include some basic sample utterances for the intent.

5.  **Slot Types:** We will define simple slot types for pizza type and quantity. For simplicity, let's assume pizza type will be a list of hardcoded values. Quantity will be an `AMAZON.NUMBER`.

Here's the Terraform configuration:

```hcl
resource "aws_lex_bot" "pizza_bot" {
  name        = "PizzaOrderBot"
  role_arn    = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:role/LexBotRole" # Replace with your actual Lex bot IAM role ARN
  timeout_seconds = 60
  voice_launch_timeout_seconds = 5
}

resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  bot_name    = aws_lex_bot.pizza_bot.name
  fulfillment_activity {
    type = "ReturnIntent"
  }
  sample_utterances = [
    "I want to order a pizza",
    "Order a pizza",
    "Can I get a pizza?",
    "Pizza please"
  ]
}

resource "aws_lex_slot_type" "pizza_type" {
  name        = "PizzaType"
  bot_name    = aws_lex_bot.pizza_bot.name
  enumeration_values = [
    "Margherita",
    "Pepperoni",
    "Vegetarian",
    "Hawaiian"
  ]
  value_selection_setting {
    resolution_strategy = "TOP_RESOLUTION"
  }
}


resource "aws_lex_slot" "pizza_type_slot" {
  name        = "pizzaType"
  intent_name = aws_lex_intent.order_pizza.name
  slot_type   = aws_lex_slot_type.pizza_type.name
  prompt {
    max_attempts = 3
    messages = [
      {
        content         = "What kind of pizza would you like?"
        content_type    = "PlainText"
      }
    ]
    response_card {
      version = 1
      text_format = "PlainText"
      text = "Choose your pizza type."
    }
  }
}

resource "aws_lex_slot" "pizza_quantity" {
  name        = "pizzaQuantity"
  intent_name = aws_lex_intent.order_pizza.name
  slot_type   = "AMAZON.NUMBER"
  prompt {
    max_attempts = 3
    messages = [
      {
        content         = "How many pizzas would you like?"
        content_type    = "PlainText"
      }
    ]
    response_card {
      version = 1
      text_format = "PlainText"
      text = "Enter the number of pizzas you want."
    }
  }
  priority = 1
}

resource "aws_lex_intent_confirmation_prompt" "confirm_order" {
  intent_name        = aws_lex_intent.order_pizza.name
  bot_name           = aws_lex_bot.pizza_bot.name
  max_attempts       = 3
  message {
    content         = "You want to order ${aws_lex_slot.pizza_quantity.name} ${aws_lex_slot.pizza_type_slot.name} pizza(s)? Please confirm."
    content_type    = "PlainText"
  }
  rejection_statement {
    content         = "Okay, let's start over."
    content_type    = "PlainText"
  }
}

data "aws_caller_identity" "current" {}

resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name        = "TestAlias"
  bot_name    = aws_lex_bot.pizza_bot.name
  bot_version = "$LATEST"
}
```

