  description = "The name of the Firehose delivery stream."
}

resource "aws_iam_role" "firehose_role" {
  name               = "${var.firehose_name}-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Effect   = "Allow",
        Sid     = ""
