resource "aws_iam_role_policy_attachment" "elasticsearch_policy" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonESFullAccess"  # Consider a more restrictive policy in production
