Okay, let's break this down into steps. We need to:

1.  **Create an IAM role:** This role will be used by the EKS cluster.  The trust policy needs to allow `eks.amazonaws.com` to assume the role.
2.  **Attach a policy to the IAM role:** We'll attach the `AmazonEKSClusterPolicy` managed policy.
3.  **Create an EKS cluster:** This cluster will use the previously created IAM role and will be configured with a provided cluster name, version, VPC configuration (private and public subnet IDs), and region.
4.  **Variables:** Accept cluster name, version, region, public subnet IDs and private subnet IDs as variables.

Now, let's put it all together in Terraform HCL.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "cluster_name" {
  type        = string
  description = "The name of the EKS cluster."
}

variable "cluster_version" {
  type        = string
  description = "The Kubernetes version of the EKS cluster."
}

variable "region" {
  type        = string
  description = "The AWS region to deploy the EKS cluster in."
}

variable "public_subnet_ids" {
  type        = list(string)
  description = "A list of public subnet IDs for the EKS cluster."
}

variable "private_subnet_ids" {
  type        = list(string)
  description = "A list of private subnet IDs for the EKS cluster."
}

resource "aws_iam_role" "eks_cluster_role" {
  name               = "eks-cluster-1"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "eks.amazonaws.com"
        },
        Effect   = "Allow",
        Sid     = ""
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "eks_cluster_policy_attachment" {
  role       = aws_iam_role.eks_cluster_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
}

resource "aws_eks_cluster" "eks_cluster" {
  name     = var.cluster_name
  version  = var.cluster_version
  region   = var.region
  role_arn = aws_iam_role.eks_cluster_role.arn

  vpc_config {
    public_subnet_ids = var.public_subnet_ids
    private_subnet_ids = var.private_subnet_ids
  }
}
```

