provider "aws" {
    region = "us-west-1"
}

data "aws_iam_policy_document" "topic" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = ["arn:aws:sns:*:*:s3-event-notification-topic"]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = [aws_s3_bucket.bucket.arn]
    }
  }
}
resource "aws_sns_topic" "topic" {
  name   = "s3-event-notification-topic"
  policy = data.aws_iam_policy_document.topic.json
}

resource "aws_s3_bucket" "bucket" {
  bucket = "your-bucket-name"
}

resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.id

  topic {
    topic_arn     = aws_sns_topic.topic.arn
    events        = ["s3:ObjectCreated:*"]
    filter_suffix = ".log"
  }
}

response:
Okay, let's break this down into steps to create the Terraform configuration.

1. **SNS Topic:** We'll create an SNS topic named `s3-event-notification-topic`.

2. **IAM Policy:**  We need an IAM policy that allows `s3.amazonaws.com` to publish to the SNS topic. This policy requires:
    *   `Effect`: "Allow"
    *   `Principal`: `s3.amazonaws.com`
    *   `Action`: `SNS:Publish`
    *   `Resource`: ARN of the SNS topic (`arn:aws:sns:<region>:<account-id>:s3-event-notification-topic`)
    *   `Condition`:  A condition that restricts publishing to only requests originating from a specific S3 bucket. This condition will use the `ArnLike` operator and a wildcard for the bucket name.

3. **S3 Bucket:** We'll create an S3 bucket named `your-bucket-name`.

4. **S3 Event Notification:** We'll configure an event notification on the S3 bucket to trigger the SNS topic when `s3:ObjectCreated:*` events occur for objects ending in `.log`.

Now, here's the Terraform code to implement these steps:

```hcl
resource "aws_sns_topic" "s3_event_topic" {
  name = "s3-event-notification-topic"
}

resource "aws_iam_policy" "s3_sns_policy" {
  name        = "S3ToSNSNotificationPolicy"
  description = "Allows S3 to publish events to SNS topic"
  policy      = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.s3_event_topic.arn
        Condition = {
          StringLike = {
            aws:SourceArn = "arn:aws:s3:::your-bucket-name/*"
          }
        }
      }
    ]
  })
}

resource "aws_s3_bucket" "s3_bucket" {
  bucket = "your-bucket-name"
}

resource "aws_s3_bucket_notification" "s3_bucket_notification" {
  bucket = aws_s3_bucket.s3_bucket.id

  event_notification {
    events = ["s3:ObjectCreated:*"]
    filters = {
      suffix = ".log"
    }
    sns_topic = aws_sns_topic.s3_event_topic.id
  }
}
```

