1.  **Create two S3 buckets:**  These will have unique names. We'll use a `random_id` resource to ensure uniqueness.
2.  **Apply ACLs:** One bucket needs to be fully private (standard default ACL). The other needs to allow `s3:PutObject` access to the logging account. We'll use an explicit ACL for this.
3.  **Enable S3 Logging:** Configure logging on the first bucket to direct logs to the second bucket with a specific prefix.
4.  **Dependencies:** Use `depends_on` to ensure resources are created in the correct order.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

resource "random_id" "private_bucket_suffix" {
  byte_length = 8
}

resource "random_id" "logging_bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket" "private_bucket" {
  bucket = "private-bucket-${random_id.private_bucket_suffix.hex}"
  acl    = "private"

  tags = {
    Name        = "Private S3 Bucket"
    Environment = "Development"
  }
}

resource "aws_s3_bucket" "logging_bucket" {
  bucket = "logging-bucket-${random_id.logging_bucket_suffix.hex}"
  acl    = "log-delivery-write"

  tags = {
    Name        = "Logging S3 Bucket"
    Environment = "Development"
  }
}

resource "aws_s3_bucket_logging" "bucket_logging" {
  bucket = aws_s3_bucket.private_bucket.id
  target_bucket = aws_s3_bucket.logging_bucket.id
  target_prefix = "log-data/"
}
```

