    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC Creation
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "private-vpc"
  }
}

# 2. Subnet Creation
resource "aws_subnet" "private_subnet_a" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with an appropriate AZ
  map_public_ip_on_launch = false # Ensure private subnet
  tags = {
    Name = "private-subnet-a"
  }
}

resource "aws_subnet" "private_subnet_b" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with an appropriate AZ
  map_public_ip_on_launch = false # Ensure private subnet
  tags = {
    Name = "private-subnet-b"
  }
}


# 3. EFS Filesystem Creation
resource "aws_efs_filesystem" "main" {
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"
  encrypted        = true

  tags = {
    Name = "shared-efs"
  }
}

# 4. Mount Target Creation
resource "aws_efs_mount_target" "main" {
  filesystem_id = aws_efs_filesystem.main.id
  subnet_id     = aws_subnet.private_subnet_a.id
  security_groups = [aws_security_group.efs.id]
}

# 5. Security Groups
resource "aws_security_group" "ec2" {
  name        = "ec2-sg"
  description = "Security group for EC2 instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "efs" {
  name        = "efs-sg"
  description = "Security group for EFS mount targets"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.private_subnet_a.cidr_block]
    # Allow EFS access from EC2 instances subnet
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 6. EC2 Instance Launch
resource "aws_instance" "instance_1" {
  ami           = "ami-0c55b349a1b8785a9" # Latest Amazon Linux 2 AMI in us-east-1
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.private_subnet_a.id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  tags = {
    Name = "ec2-instance-1"
  }

  user_data = <<-EOF
              #!/bin/bash
              mkdir /mnt/efs
              sudo mount -t efs ${aws_efs_mount_target.main.filesystem_id}:/ /mnt/efs
              EOF
}

