response:
: Okay, let's break this down into steps to create the Terraform configuration.

1.  **IAM Role Creation:** We'll need to define an IAM role with a trust relationship that allows Redshift to assume it.  We'll also need to define a policy that grants Redshift the necessary permissions (e.g., access to S3 for data loading). For simplicity, let's grant full S3 access – in a production environment, this should be scoped down to the specific buckets Redshift requires.
2.  **Redshift Cluster Creation:** We’ll define a Redshift cluster resource, specifying the cluster identifier, node type, number of nodes, database name, and the all-important `iam_roles` argument to attach the IAM role we created in step 1.
3.  **Outputs:**  We will output the Redshift cluster endpoint for easy access.

Now, here's the Terraform configuration in HCL format.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# IAM role for Redshift
resource "aws_iam_role" "redshift_role" {
  name               = "redshift-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "redshift.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

# IAM policy for Redshift (allowing full S3 access - restrict in production!)
resource "aws_iam_policy" "redshift_s3_policy" {
  name        = "redshift-s3-access-policy"
  description = "Policy granting Redshift access to S3"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "s3:*",
        Effect   = "Allow",
        Resource = "*"
      },
    ]
  })

}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "redshift_s3_attachment" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = aws_iam_policy.redshift_s3_policy.arn
}


# Redshift cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier  = "redshift-cluster-demo"
  database_name       = "demo"
  master_username     = "admin"
  master_password     = "password" # Replace with a strong password!
  node_type           = "dc2.large"
  number_of_nodes     = 2
  iam_roles           = [aws_iam_role.redshift_role.arn]
  skip_final_snapshot = true
}

# Output the Redshift cluster endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}
```

