provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Create an IAM role for the Lambda function
resource "aws_iam_role" "lambda_role" {
  name               = "lambda_execution_role"
  described_by       = "IAM role for Lambda function"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

# Attach the basic Lambda execution policy to the role
resource "aws_iam_policy_attachment" "lambda_basic_execution" {
  name       = "lambda_basic_execution"
  role_arn   = aws_iam_role.lambda_role.arn
  policy_arn = "arn:aws:iam::aws:policy/AWSLambdaBasicExecutionRole"
}

# Create a Lambda function
resource "aws_lambda_function" "example_function" {
  function_name = "my-scheduled-function"
  role          = aws_iam_role.lambda_role.arn
  runtime       = "python3.9"  #Choose a supported runtime
  handler       = "lambda_function.lambda_handler"
  zip_file      = file("lambda_function.zip") # Ensure this zip file exists

  environment {
    variables = {
      # You can define environment variables here if needed
    }
  }

}

# Create a CloudWatch Event Rule (EventBridge Rule)
resource "aws_cloudwatch_event_rule" "schedule_rule" {
  name        = "run_lambda_every_15_minutes"
  description = "Runs the Lambda function every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# Grant CloudWatch Events permission to invoke the Lambda function
resource "aws_lambda_permission" "lambda_permission" {
  statement_id  = "cloudwatch_event_invoke"
  function_name = aws_lambda_function.example_function.function_name
  action        = "lambda:InvokeFunction"
  principal    = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.schedule_rule.arn
}

