:
Okay, let's break this down into manageable steps.

1.  **Provider Configuration:** We need to configure the AWS provider, specifying the region as `us-east-1`.
2.  **VPC:** A VPC is required to contain the subnets. We’ll create a default one if it does not exist.
3.  **Subnets:** We need to create two subnets, one in `us-east-1a` and one in `us-east-1b`.  We’ll use the default VPC for these subnets.
4.  **AMI Lookup:** We need to find the latest Amazon Linux 2 AMI ID. We will use a data source to look this up.
5.  **EC2 Instances:** We will create two EC2 instances, one in each subnet, using the AMI found in the previous step. Both instances will be `t2.micro` type.
6.  **EBS Volumes:**  We will create two EBS volumes, 50GB each and attach them to the instances created.

Now, let's put it all together into the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

data "aws_vpc" "default" {
  default = true
}

data "aws_availability_zones" "available" {
  state = "available"
  region = "us-east-1"
}

data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}


resource "aws_subnet" "subnet_a" {
  vpc_id            = data.aws_vpc.default.id
  availability_zone = data.aws_availability_zones.available.names[0]
  cidr_block        = "10.0.1.0/24"
  tags = {
    Name = "subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = data.aws_vpc.default.id
  availability_zone = data.aws_availability_zones.available.names[1]
  cidr_block        = "10.0.2.0/24"
  tags = {
    Name = "subnet-b"
  }
}

resource "aws_instance" "instance_a" {
  ami           = data.aws_ami.amazon_linux.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_a.id
  tags = {
    Name = "instance-a"
  }
}

resource "aws_instance" "instance_b" {
  ami           = data.aws_ami.amazon_linux.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_b.id
  tags = {
    Name = "instance-b"
  }
}

resource "aws_ebs_volume" "volume_a" {
  availability_zone = aws_subnet.subnet_a.availability_zone
  size              = 50
  type              = "gp2"
  tags = {
    Name = "volume-a"
  }
}

resource "aws_ebs_volume" "volume_b" {
