  region = "us-east-1"
}

# 1. VPC
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

# 2. Subnets
resource "aws_subnet" "msk_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "msk-subnet-2"
  }
}

# 3. Security Groups
resource "aws_security_group" "msk_security_group" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  #WARNING: Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}


# 4. IAM Role and Policy for CloudWatch Logging
resource "aws_iam_role" "msk_cloudwatch_role" {
  name               = "msk-cloudwatch-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "kafka.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ],
  })
}

resource "aws_iam_policy" "msk_cloudwatch_policy" {
  name        = "msk-cloudwatch-policy"
  description = "Policy for MSK to send logs to CloudWatch"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:us-east-1:${data.aws_caller_identity.current.account_id}:log-group:/aws/msk/*"
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "msk_cloudwatch_attachment" {
  role       = aws_iam_role.msk_cloudwatch_role.name
  policy_arn = aws_iam_policy.msk_cloudwatch_policy.arn
}

data "aws_caller_identity" "current" {}

# 5. MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster-example"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group_info {
    client_subnets = [
