  policy_arn = aws_iam_policy.msk_policy.arn
}

# 4. Kinesis Data Firehose (replace with your actual Firehose ARN)
# Assuming Firehose is already created.  If not, you'd need to add a Firehose resource here.
resource "aws_kinesis_firehose_delivery_stream" "firehose" {
