  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_kms_key" "kms" {
    description = "kms_key_for_msk"
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    encryption_info {
        encryption_at_rest_kms_key_arn = aws_kms_key.kms.arn
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
: Okay, let's break down the requirements for creating an Amazon MSK cluster with encryption at rest using Terraform.

1.  **MSK Cluster Resource:** We'll start by defining the `aws_msk_cluster` resource.  This is the core resource for creating the cluster.
2.  **Basic Configuration:**  We need to configure basic information such as a name, Kafka and Zookeeper versions, and the number of broker nodes.
3.  **Networking:** MSK clusters need to be deployed within a VPC. We will need to reference an existing VPC and subnets.
4.  **Encryption at Rest:** MSK supports encryption at rest using AWS KMS. We need to specify the KMS key ID to use.
5.  **Broker Node Group Info:** Define the properties for the broker node group. Specification includes instance type, EBS volume size.
6.  **Security Groups:**  The MSK cluster needs security groups to control inbound and outbound traffic. Assume we have them existing.
7. **Cluster Configuration:** Define parameters like the number of Kafka brokers, monitoring parameters and logging information.

Here's the Terraform HCL code:

```hcl
resource "aws_msk_cluster" "example" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-west-2:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab"
  }
  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = 1
  }
  broker_node_group_info {
    client_subnets = [
      "subnet-0bb1c79de3EXAMPLE",
      "subnet-0bb1c79de4EXAMPLE",
      "subnet-0bb1c79de5EXAMPLE",
    ]
    instance_type   = "kafka.m5.large"
    security_groups = [
      "sg-0abcdef1234567890",
    ]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }
  vpc_config {
    subnet_ids = [
      "subnet-0bb1c79de3EXAMPLE",
      "subnet-0bb1c79de4EXAMPLE",
      "subnet-0bb1c79de5EXAMPLE",
    ]
    security_group_ids = [
      "sg-0abcdef1234567890",
    ]
  }

  tags = {
    Name = "My MSK Cluster"
  }
}

resource "aws_msk_configuration" "example" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"]
  server_properties = <<EOF
auto.create.topics.enable = true
delete.topic.enable = true
default.replication.factor = 3
min.insync.replicas = 2
log.retention.hours = 168
log.cleanup.policy = delete
offsets.retention.minutes = 1440
EOF
}
```

