}

response:
Okay, let's break this down into steps to generate the Terraform configuration.

1.  **MSK Cluster:** We'll need an `aws_msk_cluster` resource.  Important parameters include `cluster_name`, `kafka_version`, `number_of_broker_nodes`, and `broker_node_group_info`. We'll specify the region as `us-east-1`.

2.  **MSK Configuration:** We will create `aws_msk_configuration` resource. It will store the configuration to facilitate plugin usage.

3.  **MSK Connect Custom Plugin:** We'll use an `aws_msk_connect_custom_plugin` resource.  This requires the `name` and the `location` (S3 bucket and key where the `debezium.zip` file is stored). We'll assume an existing S3 bucket is available.

4.  **MSK Connect Connector:** Finally, we'll create an `aws_msk_connect_connector` resource. This resource depends on the custom plugin and the MSK cluster.  It will define the connector's `name`, `connector_configuration` (a JSON string that defines how the connector works), and links to the custom plugin.

Here's the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    client_subnets = [
      "subnet-xxxxxxxxxxxxxxxxx", # Replace with actual subnet IDs
      "subnet-yyyyyyyyyyyyyyyyy", # Replace with actual subnet IDs
      "subnet-zzzzzzzzzzzzzzzzz"  # Replace with actual subnet IDs
    ]
    instance_type   = "kafka.m5.large"
    security_groups = [
      "sg-xxxxxxxxxxxxxxxxx"   # Replace with actual security group ID
    ]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = 1
  }

  encryption_info {
    encryption_at_rest_kms_key_id = "arn:aws:kms:us-east-1:xxxxxxxxxxxx:key/yyyyyyyyyyyyyyyy" #Replace with KMS Key ARN
  }
}

resource "aws_msk_configuration" "msk_config" {
  name             = "msk-config"
  kafka_versions   = ["2.8.1"]
  server_properties = <<EOF
{
  "auto.create.topics.enable": "true",
  "delete.topic.enable": "true",
  "log.retention.hours": 168,
  "offsets.retention.minutes": 60480,
  "plugin.paths": "s3://your-s3-bucket/path-to-plugins/" #Replace with your bucket and path.
}
EOF
}


resource "aws_msk_connect_custom_plugin" "debezium_plugin" {
  name        = "debezium"
  location_s3 {
    bucket_arn = "arn:aws:s3:::your-s3-bucket/debezium.zip"  # Replace with your S3 bucket and key
    object_key = "debezium.zip"
  }
}

resource "aws_msk_connect_connector" "my_connector" {
  name                = "my-debezium-connector"
  cluster_arn         = aws_msk_cluster.msk_cluster.arn
  connector_configuration = jsonencode({
    "tasks.max": "1",
    "connector.class": "io.debezium.connector.jdbc.JdbcSourceConnector",
    "database.hostname": "your-database-host", #Replace
    "database.port": "5432", #Replace
    "database.user": "your-database-user", #Replace
    "database.password": "your-database-password", #Replace
    "database.server.name": "your-database-server-name",  #Replace
    "database.include.list": "public",       #Replace
    "table.include.list": "public.my_table", #Replace
    "plugin.name": "debezium",
  })
  capacity {
    auto_scaling {
      max_capacity = 4
      min_capacity = 1
    }
  }
}
```

