    controller_logs {
      cloudwatch_logs {
        enabled = true
        group_name = "/aws/msk/my-msk-cluster/controllers"
        log_type   = "controller"
      }
      s3 {
        enabled = true
        s3_bucket = aws_s3_bucket.msk_logs.bucket
        prefix = "msk-controller-logs"
      }
      firehose {
        enabled = true
        delivery_stream_arn = aws_kinesis_firehose_delivery_stream.msk_firehose.arn
        log_type = "controller"
      }
    }
  }
}

# MSK Configuration
resource "aws_msk_configuration" "msk_config" {
  name             = "my-msk-config"
  kafka_versions = ["2.8.1"] # match to the cluster's version
  server_properties = <<EOF
auto.create.topics.enable = true
default.replication.factor = 3
EOF
}

# S3 Bucket for logs
resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-cluster-logs-bucket" # Replace with a unique bucket name
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-stream"
  destination = "s3"
  s3_configuration {
    role_arn           = "arn:aws:iam::<account_id>:role/kinesis-firehose-role" # Replace with your Firehose role ARN
    bucket             = aws_s3_bucket.msk_logs.bucket
    prefix             = "msk-firehose-logs"
    buffering_hints {
      interval_in_seconds = 60
      size_in_mb          = 5
    }
  }
}

# Security Group
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #LIMIT THIS IN PRODUCTION
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# MSK Connect Custom Plugin
resource "aws_msk_connect_custom_plugin" "debezium_plugin" {
  name        = "debezium-plugin"
  description = "Debezium custom plugin"
  content     = file("debezium.zip") # Replace "debezium.zip" with your plugin file
}

# MSK Connect Connector
resource "aws_msk_connect_connector" "debezium_connector" {
  name        = "debezium-connector"
  capacity {
    auto_scaling {
      max_capacity = 5
      min_capacity = 1
    }
  }

  connector_configuration {
    connector_class = "io.debezium.connector.postgresql.PostgresConnector" # Replace with connector class for your use case
    tasks_max       = "1"
    database_hostname = "your_db_hostname" # Replace with your database host
    database_port = "5432" # Replace with your database port
    database_user = "your_db_user" # Replace with your database user
    database_password = "your_db_password" # Replace with your database password
    database_name = "your_db_name" # Replace with your database name
    topic_prefix = "your_topic_prefix" # Replace with desired topic prefix
 }

  service_arn = aws_msk_connect_cluster.msk_connect_cluster.arn
}

# MSK Connect Cluster
resource "aws_msk_connect_cluster" "msk_connect_cluster" {
  cluster_name = "my-msk-connect-cluster"
  min_worker_count = 1
  max_worker_count = 4
  worker_config {
    no_external_access = false
  }
}
```

Key improvements and explanations:

*   **KMS Key:** Included KMS key creation with a policy to allow MSK to use it for encryption. This is crucial for encryption at rest.
*   **MSK Configuration:** Added an MSK Configuration to define common properties for the cluster. This is best practice.
*   **Subnet IDs:**  Uses a placeholder for subnet IDs.  You *must* replace these.
*   **Security Group:** A basic security group is included to allow access on port 9092 from anywhere.  **IMPORTANT:** Restrict this to known IPs in a production environment.
*   **Logging:** Configured logging to CloudWatch Logs, S3, and Kinesis Firehose.
*   **MSK Connect:** Added configurations for MSK Connect, including a custom plugin and connector.  Placeholders are included for connection details; adjust according to your specific needs.
*    **Connector Configuration:** Added a connector configuration with sample Debezium settings. Replace placeholders with your actual database credentials and settings.
*   **Error Handling/Region:** Included a region setting and mentions potential error scenarios.
*   **Comments:** Added comments throughout the code to explain each section.
*   **Version Pinning:** Included Terraform provider version pinning for repeatability.

Before running:

*   Replace all placeholder values (subnet IDs, bucket names, KMS key policy, Firehose role ARN, database details, etc.).
*   Ensure you have the necessary IAM permissions to create these resources.
*   The `debezium.zip` file needs to be in the same directory as your Terraform configuration, or the path to the file adjusted accordingly.
*   Pay VERY close attention to the security group rules.  Opening ports to 0.0.0.0/0 is generally unacceptable for production environments.
*   Consider using Terraform state management (e.g., with an S3 bucket and DynamoDB backend) for collaboration and reliability.

