:Okay, let's break down this request and translate it into a Terraform configuration.

1.  **Cloud Provider:** The request doesn't specify a cloud provider. I'll go with Google Cloud Platform (GCP) as a default, given its robust managed database services. It's easy to adapt later if needed.
2.  **Database Service:** GCP offers Cloud SQL for MySQL. We'll use that.
3.  **High Availability/Zonal Redundancy:** The requirement for 100GB of storage "in every zone" strongly implies the need for a highly available configuration, for example, a read replica in each zone. I'll provision a primary instance and then three read replicas in different zones, each provisioned with 100GB of storage. This will achieve resilience.
4.  **Instance Configuration:** Decide on a reasonable database version and tier (db-n1-standard-1 is a decent starting point).
5.  **Networking:** Create a private service access connection so Cloud SQL can be accessible from within a VPC. We'll need a VPC network and allocated IP ranges.
6.  **IAM:** Configure appropriate IAM permissions to allow Terraform to manage Cloud SQL instances.
7.  **Considerations:** This configuration assumes a VPC network already exists or will be created separately. I'll include a basic VPC network creation to make the config self-contained, but you may need to tailor it.
8.  **Regions/Zones**: I will use `us-central1` as the region and create replicas in different zones within that region.

```hcl
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  project     = "your-gcp-project-id" # Replace with your GCP project ID
  region      = "us-central1"
}

# Create a VPC network
resource "google_compute_network" "vpc_network" {
  name                    = "mysql-vpc"
  auto_create_subnetworks = false
}

# Create a subnet in each zone
resource "google_compute_subnetwork" "subnet_us_central1_a" {
  name          = "mysql-subnet-a"
  ip_cidr_range = "10.10.1.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc_network.id
}

resource "google_compute_subnetwork" "subnet_us_central1_b" {
  name          = "mysql-subnet-b"
  ip_cidr_range = "10.10.2.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc_network.id
}

resource "google_compute_subnetwork" "subnet_us_central1_c" {
  name          = "mysql-subnet-c"
  ip_cidr_range = "10.10.3.0/24"
  region        = "us-central1"
  network       = google_compute_network.vpc_network.id
}

resource "google_sql_database_instance" "mysql_primary" {
  name             = "mysql-primary"
  region           = "us-central1"
  database_version = "MYSQL_8_0"
  settings {
    tier = "db-n1-standard-1"
    disk_autoresize = true
    disk_size_gb = 100
    backup_configuration {
      enabled = true
    }
    ip_configuration {
      private_network = google_compute_network.vpc_network.id
      authorized_networks {
        name  = "allow-internal"
        value = "10.0.0.0/8" # Adjust as needed for your internal network
      } 
    }
  }
  deletion_protection  = false
}

resource "google_sql_database_instance" "mysql_replica_a" {
  name             = "mysql-replica-a"
  region           = "us-central1"
  database_version = "MYSQL_8_0"
  settings {
    tier = "db-n1-standard-1"
    disk_autoresize = true
    disk_size_gb = 100
    backup_configuration {
      enabled = true
    }
    replication_type = "READ"
    master_instance_name = google_sql_database_instance.mysql_primary.name
    ip_configuration {
      private_network = google_compute_network.vpc_network.id
      authorized_networks {
        name  = "allow-internal"
        value = "10.0.0.0/8" # Adjust as needed for your internal network
      }
    }

  }
  deletion_protection  = false
}

resource "google_sql_database_instance" "mysql_replica_b" {
