  cidr_block = "10.1.0.0/16"
  tags = {
    Name = "vpc-a"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id     = aws_vpc.vpc_a.id
  cidr_block = "10.1.1.0/24"
  tags = {
    Name = "subnet-a"
  }
}

