response:
 Okay, let's break down the creation of an AWS Neptune cluster with a custom parameter group and subnet restrictions in Terraform.

1.  **Neptune Subnet Group:** We need a Neptune subnet group to specify which subnets Neptune instances can reside in. The request specifies two subnets, so we'll use those.
2.  **Neptune Cluster Parameter Group:** Neptune uses parameter groups to configure cluster behavior. We’ll create a custom one, allowing for specific settings (though we won't define specific parameters in this example, the resource is needed).
3.  **Neptune Cluster:** This is the core resource. We’ll define its engine version, instance size, and associate it with the subnet group and parameter group.
4.  **Security Group:** A security group will be configured to restrict inbound access to the Neptune cluster. We'll allow access only from the specified subnets.
5.  **AWS Provider:** Configuration for the AWS provider.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. Neptune Subnet Group
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with your subnet IDs
  tags = {
    Name = "Neptune Subnet Group"
  }
}

# 2. Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "neptune_cluster_parameter_group" {
  name   = "neptune-cluster-params"
  family = "neptune-db"
  description = "Custom Neptune cluster parameter group"
}

# 3. Security Group
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-sg"
  description = "Security group for Neptune cluster"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["subnet-xxxxxxxxxxxxxxxxx/24", "subnet-yyyyyyyyyyyyyyyyy/24"] # Allow access from specified subnets
  }

  ingress {
    from_port   = 81
    to_port     = 81
    protocol    = "tcp"
    cidr_blocks = ["subnet-xxxxxxxxxxxxxxxxx/24", "subnet-yyyyyyyyyyyyyyyyy/24"] # Allow access from specified subnets
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Neptune Security Group"
  }
}

# 4. Neptune Cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier = "neptune-cluster"
  engine             = "neptune"
  engine_version     = "1.2" # Specify the desired Neptune engine version
  instance_class     = "neptune-db.r5.large"
  vpc_security_group_ids = [aws_security_group.neptune_sg.id]
  db_subnet_group_name = aws_neptune_subnet_group.neptune_subnet_group.name
  cluster_parameter_group_name = aws_neptune_cluster_parameter_group.neptune_cluster_parameter_group.name
  skip_final_snapshot = true # Set to false for production environments.
  tags = {
    Name = "Neptune Cluster"
  }
}
