response:
: Okay, let's break this down into steps to create the Terraform configuration:

1.  **VPC:** We'll start by defining an AWS VPC with a CIDR block.
2.  **Subnets:**  Create two public subnets within the VPC, suitable for Redshift. We'll assign them different Availability Zones.
3.  **Subnet Group:**  Create an AWS Redshift Subnet Group, associating it with the two previously created subnets.
4.  **Redshift Cluster:** Define the Redshift cluster resource, specifying the cluster identifier, node type, database name, master username/password, and crucially, associate it with the subnet group created earlier.
5. **Endpoint Access:** Create an endpoint access resource that allows client access to the Redshift cluster.

Here's the Terraform configuration in HCL format to implement that:

```hcl
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

}

resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier = "redshift-cluster-demo"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = "P@sswOrd123" #Please replace with a strong password
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  skip_final_snapshot = true
  subnet_group_name  = aws_redshift_subnet_group.redshift_subnet_group.name
}

resource "aws_redshift_endpoint_access" "redshift_endpoint_access" {
  cluster_identifier = aws_redshift_cluster.redshift_cluster.id
  address            = "0.0.0.0/0" # Be very careful with this; ideally restrict to specific IP ranges
}
```

