response:
:
Okay, let's break down the requirements to create this Terraform configuration.

1.  **Redshift Cluster:** We need to define a `aws_redshift_cluster` resource. The request asks for "sample cluster settings," so we'll use reasonable defaults for a development/test cluster – a node type, number of nodes, database name, etc.
2.  **Parameter Group:** We need an `aws_redshift_parameter_group` resource. This is what we will be setting up notifications on.
3.  **Event Subscription:** We need to configure event notifications. Redshift events are subscribed to via Amazon SNS. We'll use `aws_redshift_event_subscription` for this. This requires setting up an SNS topic first (`aws_sns_topic`).
4.  **IAM Role:** Redshift needs permissions to publish events to SNS. We need to create an IAM role (`aws_iam_role`) and policy (`aws_iam_policy`) for it.
5.  **Dependencies:** The event subscription depends on the cluster, the parameter group, the SNS topic and the IAM Role.

Here's the Terraform configuration:

```hcl
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-events-topic"
}

resource "aws_iam_policy" "redshift_sns_policy" {
  name        = "RedshiftSnsPolicy"
  description = "Allows Redshift to publish events to SNS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "sns:Publish"
        Effect   = "Allow"
        Resource = aws_sns_topic.redshift_events.arn
      }
    ]
  })
}

resource "aws_iam_role" "redshift_event_role" {
  name               = "RedshiftEventRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action  = "sts:AssumeRole"
        Effect  = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_event_policy" {
  role       = aws_iam_role.redshift_event_role.name
  policy_arn = aws_iam_policy.redshift_sns_policy.arn
}


resource "aws_redshift_parameter_group" "default" {
  name = "my-redshift-parameter-group"
  family = "redshift-1.0"
}

resource "aws_redshift_cluster" "default" {
  cluster_identifier      = "my-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "password"  # Replace with a strong password!
  node_type               = "dc2.large"
  number_of_nodes         = 2
  cluster_type            = "single-node"
  skip_final_snapshot     = true
  parameter_group_name    = aws_redshift_parameter_group.default.name
  iam_roles               = [aws_iam_role.redshift_event_role.arn]
}


resource "aws_redshift_event_subscription" "default" {
  name          = "my-redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_events.arn
  source_type   = "parametergroup"
  source_identifier = aws_redshift_parameter_group.default.name
  event_categories = ["parameter group"]
  status = "active"

  depends_on = [
    aws_redshift_cluster.default,
    aws_redshift_parameter_group.default,
    aws_sns_topic.redshift_events,
    aws_iam_role_policy_attachment.redshift_event_policy
  ]
}
```

