3.  **Configure S3 Analytics on the primary bucket.**  Crucially, we'll use the *ARN* of the destination bucket within the analytics configuration.  This is the resource reference part of the requirement.

Here's the Terraform code to achieve this:

```hcl
resource "aws_s3_bucket" "primary" {
  bucket = "mybucket"
  acl    = "private"

  tags = {
    Name        = "mybucket"
    Environment = "dev"
  }
}

resource "aws_s3_bucket" "analytics" {
  bucket = "mybucket-analytics"
  acl    = "private"

  tags = {
    Name        = "mybucket-analytics"
    Environment = "dev"
  }
}

resource "aws_s3_bucket_analytics_configuration" "analytics_config" {
  bucket = aws_s3_bucket.primary.id
  data_frequency = "Daily"

  storage {
    location {
      bucket = aws_s3_bucket.analytics.id
    }
    format = "CSV"
  }
}
```

