response:
Okay, let's break down the requirements for a CS course autograding system on AWS using Terraform.

1.  **S3 Bucket:** We need an S3 bucket to store student submissions (pulled from GitHub), grading outputs, and potentially any logs.
2.  **IAM Role for CodeBuild:** CodeBuild needs permissions to access the S3 bucket (read submissions, write results), access GitHub (read repository contents), and potentially CloudWatch for logging.
3.  **CodeBuild Project:** This will be the core of the autograding system. It will:
    *   Be triggered by some event (e.g., a push to a specific branch in a repository, or a scheduled event).
    *   Pull student submissions from GitHub.
    *   Execute the submissions within a defined environment (e.g., a Docker container with specific tools installed).
    *   Save grading outputs to the S3 bucket.
4. **GitHub Connection:**  AWS CodeBuild needs a connection to GitHub so that it can access the student submissions.
5.  **Security:** Least privilege principle; grant only the necessary permissions.
6.  **Variables:** Parameterize bucket name, GitHub repository, branch, CodeBuild instance type, and other configurable parameters.

Now, let's translate this to Terraform.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Variables
variable "bucket_name" {
  type        = string
  description = "Name of the S3 bucket to store submissions and outputs"
  default     = "cs-autograding-bucket-unique" # Replace with a unique name
}

variable "github_repository" {
  type        = string
  description = "The GitHub repository containing student submissions."
}

variable "github_branch" {
  type        = string
  description = "The branch in the GitHub repository to monitor."
  default     = "main"
}


variable "codebuild_instance_type" {
  type        = string
  description = "The instance type for CodeBuild."
  default     = "build.standard.large"
}

variable "environment_image" {
  type        = string
  description = "The Docker image to use for the CodeBuild environment. Needs to have grading tools installed."
  default     = "amazon/aws-codebuild-docker:latest"
}


# S3 Bucket for Storing Submissions and Outputs
resource "aws_s3_bucket" "s3_bucket" {
  bucket = var.bucket_name
  acl    = "private"

  tags = {
    Name        = "cs-autograding-bucket"
    Environment = "Production"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild-policy"
  description = "Policy for CodeBuild to access S3 and GitHub"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          "arn:aws:s3:::${var.bucket_name}",
          "arn:aws:s3:::${var.bucket_name}/*"
        ]
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Action = [
            "github:ReadRepository"
        ],
        Effect = "Allow",
        Resource = "*"
      }
    ]
  })
}


resource "aws_iam_role_policy_attachment" "codebuild_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# GitHub Connection
resource "aws_codebuild_source_credential" "github_connection" {
  provider_type = "GITHUB"
  auth_token    = "YOUR_GITHUB_TOKEN" # Replace with your GitHub personal access token
}


# CodeBuild Project
resource "aws_codebuild_project" "autograding_project" {
  name         = "cs-autograding-project"
  description  = "CodeBuild project for autograding CS submissions"

  source {
    type      = "GITHUB"
    location  = var.github_repository
    branch    = var.github_branch
    report_build_status = false
  }

  environment {
    image     = var.environment_image
    type      = "LINUX_CONTAINER"
    compute_type = "BUILD_STANDARD"
    instance_type = var.codebuild_instance_type
  }

  artifacts {
    type = "S3"
    location = var.bucket_name
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.bucket_name}-logs"
      stream_name = "autograding-stream"
    }
  }

  service_role = aws_iam_role.codebuild_role.arn
}
