Okay, let's break this down. We need to create two resources: an S3 bucket and a CodeBuild project.

1.  **S3 Bucket:** A standard S3 bucket will suffice for storing artifacts. We'll need to generate a unique bucket name.
2.  **CodeBuild Project:** This is more involved. We need to define the `source`, `environment`, and `artifacts` blocks as per the request. The environment is a Linux container based on `alpine`, and the source is a GitHub repository. We will use a hardcoded bucket name for simplicity

```hcl
resource "aws_s3_bucket" "artifacts_bucket" {
  bucket = "my-unique-artifact-bucket" # Replace with a unique bucket name
  acl    = "private"

  tags = {
    Name        = "Artifacts Bucket"
    Environment = "Development"
  }
}

resource "aws_codebuild_project" "artifact_builder" {
  name         = "artifact-builder-project"
  description  = "Build project to store artifacts in S3"

  source {
    type            = "GITHUB"
    git_clone_depth = 1
    location        = "github.com/source-location"  #Replace with your repository location
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "alpine"
    type         = "LINUX_CONTAINER"
  }

  artifacts {
    type = "S3"
    paths = ["*"] # Adjust this to include only the desired build outputs
    bucket = aws_s3_bucket.artifacts_bucket.bucket
  }
}
