  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway (for CodeBuild to pull code - potentially restrict outbound later)
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "Main Internet Gateway"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}


# Security Groups
resource "aws_security_group" "codebuild" {
  name        = "codebuild-sg"
  description = "Security group for CodeBuild"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"] # Allow all outbound, limit if necessary
  }
}

# S3 Bucket
resource "aws_s3_bucket" "results" {
  bucket = var.bucket_name
  acl    = "private"

  tags = {
    Name = "autograding-results"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })

  inline_policy {
    name = "codebuild-policy"
    policy = jsonencode({
      Version = "2012-10-17",
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:PutObject",
          ],
          Effect   = "Allow",
          Resource = [
            "arn:aws:s3:::${var.bucket_name}/*",
            "arn:aws:s3:::${var.bucket_name}"
          ],
        },
        {
          Action = [
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
            "logs:PutLogEvents",
          ],
          Effect   = "Allow",
          Resource = "arn:aws:logs:*:*:*"
        },
        {
          Action = [
            "codecommit:GitPull"
          ],
          Effect = "Allow",
          Resource = "*" # Ideally, restrict to specific repositories
        },
         {
          Action = [
            "github:PullRequest"
          ],
          Effect = "Allow",
          Resource = [
            "arn:aws:github:*:*:repository/${var.github_owner}/${var.github_repo}"
          ]
        }

      ],
    })
  }
}

