response:
Okay, let's break down the requirements and design a Terraform configuration for an autograding system using AWS.

**1. Core Components:**

*   **VPC:**  A Virtual Private Cloud to isolate the grading environment. This is crucial for security – student code should *not* have internet access.
*   **Subnets:** Public and Private subnets within the VPC. CodeBuild will likely run in a public subnet so it can pull the code from GitHub (we might still restrict outbound internet access for CodeBuild later).
*   **Security Groups:**  Security groups to control network traffic.  We'll need one for CodeBuild to allow inbound from specific sources (e.g., the user initiating the build or perhaps an AWS Systems Manager Session Manager connection). Another for any compute instances potentially used by student code – this one will be very restrictive, allowing only internal communication.
*   **AWS CodeBuild:** The core execution engine for running student code. We'll configure it to pull code from GitHub, execute tests, and report results.
*   **IAM Roles:** IAM roles for CodeBuild with permissions to access the GitHub repository and potentially write grading results to S3.
*   **S3 Bucket:** An S3 bucket to store grading results, logs, and potentially student submissions.
*   **GitHub Integration:**  While Terraform won't directly handle the GitHub integration (e.g., setting up webhooks), it will configure the IAM role appropriately to allow CodeBuild to access GitHub.

**2. Terraform Structure:**

We will define the following in the Terraform configuration:

*   AWS Provider configuration
*   VPC with subnets
*   Security Groups
*   S3 Bucket
*   IAM Role for CodeBuild

**3. Configuration Details**

*   We will use variables for values that might change or are environment-specific (e.g., AWS region, GitHub owner/repo).
*   The security group associated with CodeBuild will allow inbound connections from anywhere (0.0.0.0/0) on port 22 for debugging purposes (SSH). This should be locked down in a production environment.
*   An S3 bucket will store results.



```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# Variables
variable "aws_region" {
  type    = string
  default = "us-east-1"
}

variable "vpc_cidr" {
  type    = string
  default = "10.0.0.0/16"
}

variable "public_subnet_cidr" {
  type    = string
  default = "10.0.1.0/24"
}

variable "private_subnet_cidr" {
  type    = string
  default = "10.0.2.0/24"
}

variable "github_owner" {
  type    = string
  default = "your-github-owner"
}

variable "github_repo" {
  type    = string
  default = "your-github-repo"
}

variable "bucket_name" {
  type = string
  default = "autograding-results-bucket"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = var.vpc_cidr
  tags = {
    Name = "autograding-vpc"
  }
}

# Subnets
resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = var.public_subnet_cidr
  availability_zone = "${var.aws_region}a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = var.private_subnet_cidr
  availability_zone = "${var.aws_region}b"
  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway (for CodeBuild to pull code - potentially restrict outbound later)
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "Main Internet Gateway"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}


# Security Groups
resource "aws_security_group" "codebuild" {
  name        = "codebuild-sg"
  description = "Security group for CodeBuild"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"] # Allow all outbound, limit if necessary
  }
}

# S3 Bucket
resource "aws_s3_bucket" "results" {
  bucket = var.bucket_name
  acl    = "private"

  tags = {
    Name = "autograding-results"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ],
  })

  inline_policy {
    name = "codebuild-policy"
    policy = jsonencode({
      Version = "2012-10-17",
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:PutObject",
          ],
          Effect   = "Allow",
          Resource = [
            "arn:aws:s3:::${var.bucket_name}/*",
            "arn:aws:s3:::${var.bucket_name}"
          ],
        },
        {
          Action = [
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
            "logs:PutLogEvents",
          ],
          Effect   = "Allow",
          Resource = "arn:aws:logs:*:*:*"
        },
        {
          Action = [
            "codecommit:GitPull"
          ],
          Effect = "Allow",
          Resource = "*" # Ideally, restrict to specific repositories
        },
         {
          Action = [
            "github:PullRequest"
          ],
          Effect = "Allow",
          Resource = [
            "arn:aws:github:*:*:repository/${var.github_owner}/${var.github_repo}"
          ]
        }

      ],
    })
  }
}
