  description = "The name of the S3 bucket"
}

variable "github_repository_url" {
  type        = string
  description = "The URL of the GitHub repository containing student submissions"
}

variable "vpc_cidr" {
  type    = string
  default = "10.0.0.0/16"
}

variable "subnet_cidr" {
  type    = string
