}

# VPC
resource "aws_vpc" "autograding_vpc" {
  cidr_block = var.vpc_cidr
  tags = {
    Name = "autograding-vpc"
  }
}

# Subnet
resource "aws_subnet" "autograding_subnet" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = var.subnet_cidr
  availability_zone = "${var.aws_region}a" #consider changing
  tags = {
    Name = "autograding-subnet"
  }
}

# Security Group - IMPORTANT: No outbound access!
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-sg"
  description = "Security group for CodeBuild, blocking all outbound internet"
  vpc_id      = aws_vpc.autograding_vpc.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict as needed, example allow all.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["127.0.0.1/32"] # Only allow traffic to localhost
  }

  tags = {
    Name = "codebuild-sg"
  }
}

# S3 Bucket
resource "aws_s3_bucket" "autograding_bucket" {
  bucket = var.s3_bucket_name
  tags = {
    Name = "autograding-bucket"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild-policy"
  description = "Policy for CodeBuild to access S3 and GitHub"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.autograding_bucket.arn,
          "${aws_s3_bucket.autograding_bucket.arn}/*"
        ]
      },
      # Add permissions to access GitHub - OAuth or IAM
      # Replace with correct permissions based on authentication method
      {
        Effect = "Allow",
        Action = [
          "sts:AssumeRole"
        ],
        Resource = "arn:aws:iam::*:role/..." # Replace with correct IAM Role Arn of GitHub connection
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild Project
resource "aws_codebuild_project" "autograding_project" {
  name         = "autograding-project"
  description  = "CodeBuild project for autograding"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type = "GITHUB"
    location = var.github_repository_url
    buildspec = "buildspec.yml" #Consider using inline buildspec or customize
  }

  environment {
    type = "LINUX"
    image = "aws/codebuild/standard:5.0"  # Choose an appropriate image
    compute_type = "BUILD_GENERAL1_SMALL" #Choose appropriate compute
  }

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograding_bucket.bucket
  }

  vpc_config {
    security_group_ids = [aws_security_group.codebuild_sg.id]
    subnet_ids         = [aws_subnet.autograding_subnet.id]
  }
}
