Okay, let's break this down into steps to build the Terraform configuration.

1. **S3 Bucket:** We'll create a standard S3 bucket to store build artifacts.
2. **VPC:** Create a VPC with the specified CIDR block.
3. **Subnet:** Create a public subnet within the VPC with the specified CIDR block.
4. **Security Group:** Create a security group associated with the VPC and configure it for no ingress/egress access.
5. **CodeBuild Project:**
   - Define the `artifacts` block to store outputs in the S3 bucket.
   - Configure the `environment` block with the desired compute type, image, and environment type.
   - Define the `source` block for GitHub with shallow cloning and the repository location.
   - Link the project to the VPC using the `vpc_config` block.

Now, here's the HCL code:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

# S3 Bucket for CodeBuild Artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "unique-codebuild-artifacts-bucket"  # Replace with a unique bucket name
  acl    = "private"

  tags = {
    Name        = "CodeBuild Artifacts Bucket"
    Environment = "Development"
  }
}

# VPC
resource "aws_vpc" "codebuild_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "CodeBuild VPC"
  }
}

# Subnet
resource "aws_subnet" "codebuild_subnet" {
  vpc_id            = aws_vpc.codebuild_vpc.id
  cidr_block        = "10.0.0.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ

  tags = {
    Name = "CodeBuild Subnet"
  }
}

# Security Group - No Ingress/Egress
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-sg"
  description = "Security group with no ingress or egress for CodeBuild"
  vpc_id      = aws_vpc.codebuild_vpc.id

  ingress {}
  egress {}

  tags = {
    Name = "CodeBuild Security Group"
  }
}

# CodeBuild Project
resource "aws_codebuild_project" "build_project" {
  name         = "my-codebuild-project" # Replace with desired project name
  description  = "CodeBuild project for building artifacts"

  source {
    type            = "GITHUB"
    location        = "github.com/source-location" # Replace with your repo URL
    git_clone_depth = 1
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "alpine"
    compute_type    = "BUILD_GENERAL1_SMALL"
  }

  artifacts {
    type = "S3"
    paths = ["*"]
    bucket = aws_s3_bucket.codebuild_artifacts.bucket
    name = "build-artifacts"
  }

  vpc_config {
    security_group_ids = [aws_security_group.codebuild_sg.id]
    subnet_ids         = [aws_subnet.codebuild_subnet.id]
  }
}
