}

response:
Okay, let's break this down into steps to build the Terraform configuration.

1.  **Lambda Function:** We'll start by defining the AWS Lambda function resource. This will include the function name, source code location, handler, and runtime.
2.  **EventBridge Rule:** We'll define the EventBridge rule. This will specify the schedule expression (cron) and link it to the Lambda function using a target.
3.  **Lambda Permission:** Finally, we'll add the necessary permission to the Lambda function allowing EventBridge to invoke it.

Now, I’ll structure the HCL code incorporating these three components.

```hcl
resource "aws_lambda_function" "cron" {
  function_name = "cron-lambda-function"
  filename      = "./supplement/lambda_func.zip"
  handler       = "lambda_func.lambda_handler"
  runtime       = "python3.12"
  role          = aws_iam_role.lambda_role.arn # Assuming a role exists for Lambda execution.
}

resource "aws_iam_role" "lambda_role" {
  name        = "lambda_execution_role"
  description = "Role for Lambda execution"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy" "lambda_policy" {
  name        = "lambda_policy"
  description = "Policy for Lambda execution"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_role_policy" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

resource "aws_eventbridge_rule" "cron" {
  name        = "cron"
  schedule_expression = "cron(0 7 * * ? *)"

  tags = {
    Name = "cron"
  }
}

resource "aws_eventbridge_target" "cron" {
  rule      = aws_eventbridge_rule.cron.name
  target_id = "cronLambdaTarget"
  arn       = aws_lambda_function.cron.arn
}

resource "aws_lambda_permission" "cron" {
  function_name = aws_lambda_function.cron.function_name
  action        = "lambda:InvokeFunction"
  principal     = "events.amazonaws.com"
  source_arn    = aws_eventbridge_rule.cron.arn
}
```

