reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "video_content" {
  bucket_prefix = "video-content-"
}

resource "aws_s3_object" "put_website" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "index.html"
  source = "./supplement/index.html"
  content_type = "text/html"
}

resource "aws_s3_object" "put_website_css" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "css/style.css"
  source = "./supplement/css/style.css"
  content_type = "text/css"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.my_distribution.arn
          }
        }
      }
    ]
  })
}


locals {
  s3_origin_id = "s3_video_content_origin"
}

resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "s3-oac"
  description                       = "aws access control policy"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "my_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = local.s3_origin_id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
  }

  price_class = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Route53
resource "aws_route53_zone" "my_zone" {
  name = "my-test-cloudfront.com"
}

resource "aws_route53_record" "cdn_ipv4" {
  type    = "A"
  name    = "cdn"
  zone_id = aws_route53_zone.my_zone.zone_id

  alias {
    name                   = aws_cloudfront_distribution.my_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.my_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

response:
Okay, let's break down the requirements and build the Terraform configuration.

1.  **S3 Bucket:** We need an S3 bucket to store the video content. This bucket needs to be configured for static website hosting to serve the videos directly. We should also enable versioning for recovery purposes.  We'll want to restrict public access.

2.  **CloudFront Distribution:**  Here's where things get a bit more involved. This is the CDN. 
    *   **Origin:** The origin will be the S3 bucket.
    *   **Origin Access Identity (OAI):**  We'll need an OAI so CloudFront can access the S3 bucket (which is otherwise private) without making the bucket publicly accessible directly.
    *   **Default Cache Behavior:**  Handle all requests to our domain. Configure caching parameters as appropriate (TTL).
    *   **Viewer Protocol Policy:** Redirect HTTP to HTTPS.
    *   **Price Class:** Choose a price class based on the target audience's geographical locations.
    *   **Alternate Domain Names (CNAMEs):** We need to designate custom domain names to point to CloudFront.  (For demonstration, I'll use a placeholder).
    *   **SSL Certificate:**  An SSL/TLS certificate is necessary for HTTPS.  I will assume one exists in the AWS Certificate Manager.



Here's the Terraform code:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# S3 Bucket for Video Storage
resource "aws_s3_bucket" "video_bucket" {
  bucket = "my-video-streaming-bucket-${random_string("suffix", 6)}" # Replace with your bucket name and add randomness
  acl    = "private"  # Ensure bucket is private
  versioning {
    enabled = true
  }

  tags = {
    Name = "Video Streaming Bucket"
  }
}

# CloudFront Origin Access Identity
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for accessing the S3 bucket"
}

# Update bucket policy to grant CloudFront access
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid    = "GrantCloudFrontAccess",
        Effect = "Allow",
        Principal = {
          AWS = "${aws_cloudfront_origin_access_identity.oai.id}"
        },
        Action   = "s3:GetObject",
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}


# CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name               = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id                 = "S3-Video-Origin"
    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.id
    }

  }

  default_cache_behavior {
    target_origin_id = "S3-Video-Origin"

    viewer_protocol_policy = "redirect-to-https"
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies      = false
    }
    min_ttl          = 0
    default_ttl      = 3600
    max_ttl          = 86400
  }

  price_class = "UseOnlyCloudFrontRegions" #Optimize for cost/performance

  viewer_certificate {
    cloudfront_default_certificate = false
    acm_certificate_arn      = "arn:aws:acm:us-east-1:123456789012:certificate/your-certificate-id"  # Replace with your ACM certificate ARN
    ssl_support_method       = "sni-only"
  }

  aliases = ["videos.example.com"] # Replace with your domain name

  tags = {
    Name = "Video Streaming Distribution"
  }
}

# Output the CloudFront domain name
output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.video_distribution.domain_name
}
