response:
Okay, let's break this down into steps to build the Terraform configuration for a global video streaming platform infrastructure on AWS.

1.  **S3 Bucket**: We'll need an S3 bucket to store the video content.  Enable bucket versioning for rollback capabilities. Configure block public access to ensure content is served solely through the CDN.
2.  **Origin Access Control (OAC)**: Create an OAC to securely restrict access to the S3 bucket to only the CloudFront distribution.
3.  **CloudFront Distribution**: Create a CloudFront distribution that uses the S3 bucket as its origin, configured with the OAC. Configure caching based on common video streaming patterns. We'll set a default root object for convenience. Enable logging to an S3 bucket for analysis and troubleshooting.
4.  **Route 53 Hosted Zone**: We'll need a Route 53 hosted zone to manage the DNS records for the platform's domain.
5.  **Route 53 Record**: Create an alias record in the hosted zone to point to the CloudFront distribution.
6.  **IAM Roles and Policies**: Create the necessary IAM roles and policies for the CloudFront distribution to access the S3 bucket via the OAC.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # You can change this to your preferred region
}

# 1. S3 Bucket
resource "aws_s3_bucket" "video_bucket" {
  bucket = "your-video-platform-bucket" # Replace with your desired bucket name
  acl    = "private"

  versioning {
    enabled = true
  }

  block_public_access {
    block_public_acls     = true
    block_public_policy    = true
    ignore_public_acls     = true
    restrict_public_buckets = true
  }

  tags = {
    Name        = "Video Platform Bucket"
    Environment = "Production"
  }
}

# 2. Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "oac" {
  name              = "video-oac"
  origin_access_control_config {
    signing_behavior = "always"
    signing_protocol = "sigv4"
  }
}

# 3. CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  comment = "CloudFront distribution for video streaming"

  origins {
    domain_name = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id   = "video-origin"

    s3_origin_config {
      origin_access_control = aws_cloudfront_origin_access_control.oac.id
    }
  }

  default_root_object = "index.html" # Or your preferred default video file

  default_cache_behavior {
    target_origin_id = "video-origin"

    viewer_protocol_policy = "redirect-to-https"
    allowed_methods         = ["GET", "HEAD"]
    cached_methods          = ["GET", "HEAD"]

    forwarded_values {
      query_string = false
      cookies      = {
        forward = "none"
      }
    }

  }

  price_class = "UseOnlyLowerPrices"

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.video_bucket.bucket
    prefix          = "cloudfront-logs/"
  }

  tags = {
    Name        = "Video Platform CDN"
    Environment = "Production"
  }
}

# 4. Route 53 Hosted Zone
resource "aws_route53_zone" "video_zone" {
  name = "yourdomain.com" # Replace with your domain name

  tags = {
    Name        = "Video Platform DNS Zone"
    Environment = "Production"
  }
}

# 5. Route 53 Record
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "cdn.yourdomain.com" # Replace with your desired subdomain
  type    = "A"

