  }
}

# Launch Configuration
resource "aws_launch_template" "video_server_lt" {
  name_prefix   = "video-server-"
  image_id      = "ami-0c55bca456d77eb54" # Amazon Linux 2 AMI - us-east-1. Replace with your desired AMI.
  instance_type = "t2.micro" # Change this to a suitable instance type for video streaming
  key_name      = "your_key_name" # Replace with your EC2 keypair name

  network_interfaces {
    associate_public_ip_address = false
