  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Instances
resource "aws_instance" "video_streaming_instance" {
  count         = 3
  ami           = "ami-0c55b44b89c432e8a" # Replace with a suitable AMI for your region and OS
  instance_type = "t2.micro" # Adjust the instance size as needed
  subnet_id     = element(module.vpc.public_subnets, count % length(module.vpc.public_subnets))
  vpc_security_group_ids = [aws_security_group.video_streaming_sg.id]

  tags = {
    Name = "VideoStreamingServer-${count.index}"
  }
}

# Load Balancer Target Group
resource "aws_lb_target_group" "video_streaming_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path     = "/" # Adjust the health check path as needed
    protocol = "HTTP"
    interval = 30
    timeout  = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

# Load Balancer
resource "aws_lb" "video_streaming_lb" {
  name               = "video-streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.video_streaming_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false  # set to true in production

  access_logs {
    storage_bucket  = "your-s3-bucket-for-logs" # Replace with your S3 bucket name
    storage_prefix  = "video-streaming-lb-logs"
    storage_bucket_owner = false
  }
}

# Load Balancer Listener
resource "aws_lb_listener" "video_streaming_listener" {
  load_balancer_arn = aws_lb.video_streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  }
}

# Register EC2 Instances with Target Group
resource "aws_lb_target_group_attachment" "video_streaming_attachment" {
  count            = length(aws_instance.video_streaming_instance)
  target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  instance_id      = aws_instance.video_streaming_instance[count.index].id
