response:
Okay, let's break down this request and translate it into a Terraform configuration. Here's the plan:

1.  **VPC:** Create a VPC with the specified CIDR block.
2.  **Subnets:** Create three subnets within the VPC, each with its assigned CIDR block.
3.  **Security Group:** Create a security group associated with the VPC.  Define ingress and egress rules for port 80 as requested.
4.  **Application Load Balancer (ALB):** Create an ALB, associating it with the subnets and security group. Set `load_balancer_type` to "application".
5.  **Target Group:** Create a target group for the ALB, specifying the VPC, port 80, and HTTP protocol.
6.  **Listener:** Create a listener for the ALB, directing traffic to the target group.
7.  **EC2 Instance:** Launch an EC2 instance with the latest Ubuntu AMI.
8.  **Target Group Attachment:** Register the EC2 instance with the target group.
9.  **Route53 Hosted Zone:** Create a hosted zone for `test-video-stream.com`.
10. **Route53 Alias Records:** Create two alias records for `lb.test-video-stream.com` pointing to the ALB's DNS name for both IPv4 (A) and IPv6 (AAAA) addressing, with health checks enabled.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

# 2. Subnets
resource "aws_subnet" "subnet_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.4.0/24"
  tags = {
    Name = "subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.5.0/24"
  tags = {
    Name = "subnet-2"
  }
}

resource "aws_subnet" "subnet_3" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.6.0/24"
  tags = {
    Name = "subnet-3"
  }
}

# 3. Security Group
resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow inbound traffic on port 80"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Application Load Balancer
resource "aws_lb" "main" {
  name               = "main-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id, aws_subnet.subnet_3.id]

  tags = {
    Name = "main-alb"
  }
}

# 5. Target Group
resource "aws_lb_target_group" "main" {
  name     = "main-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
  health_check {
    path = "/"
  }
}

# 6. Listener
resource "aws_lb_listener" "main" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

# 7. EC2 Instance
data "aws_ami" "ubuntu" {
  most_recent = true

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-jammy-22.04-amd64-server-*"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  owners = ["099739979999"] # Canonical
}

resource "aws_instance" "example" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_1.id #Example subnet
  vpc_security_group_ids = [aws_security_group.alb_sg.id]

  tags = {
    Name = "example-instance"
  }
}

# 8. Target Group Attachment
resource "aws_lb_target_group_attachment" "main" {
  target_group_arn = aws_lb_target_group.main.arn
  target_id        = aws_instance.example.id
  port             = 80
}

# 9. Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "test-video-stream.com"
}

# 10. Route53 Alias Records
resource "aws_route53_record" "lb_a" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "lb.test-video-stream.com"
  type    = "A"
  set_identifier = "lb-a"
  alias {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "lb_aaaa" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "lb.test-video-stream.com"
  type    = "AAAA"
  set_identifier = "lb-aaaa"
  alias {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}
```

