  db_parameter_group_name = aws_db_parameter_group.default.name
  skip_final_snapshot  = true

  tags = {
    Name = "my-postgresql-instance"
  }
}

# Outputs
output "rds_endpoint" {
  value = aws_db_instance.default.endpoint
}

output "rds_id" {
  value = aws_db_instance.default.id
}

