terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 50
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
Okay, let's break down the Terraform configuration needed for this request step by step:

1.  **VPC**: Assume a VPC already exists. We'll need the VPC ID and at least two subnets within that VPC for Multi-AZ deployment. We'll also need details for the subnet group.
2.  **Subnet Group**: An RDS subnet group will map the database to the specified subnets within the VPC for availability zones.
3.  **KMS Key**: A KMS key will be used for encrypting the database. We'll need its ARN or will create one.
4.  **Security Group**: A security group will control inbound and outbound traffic to the RDS instance. We'll need to specify rules to allow access (likely from bastion hosts or other application servers).
5.  **DB Parameter Group**: A custom DB parameter group will let us specify configuration options like `shared_buffers` or other PostgreSQL settings.  We'll create one.
6.  **RDS Instance**: The core RDS instance resource will pull all these components together to create the database. We'll configure the engine version (PostgreSQL 15), instance size, storage, Multi-AZ, and encryption.
7.  **Outputs**: We'll output the endpoint and name of the RDS instance for easy access and connection.

Here's the Terraform configuration in HCL format:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Data source for existing VPC
data "aws_vpc" "selected" {
  id = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID
}

# Data source for subnets
data "aws_subnets" "private" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.selected.id]
  }

  tags = {
    "Name" = "PrivateSubnet"
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "my-rds-subnet-group"
  subnet_ids = data.aws_subnets.private.ids
}


# KMS Key (You can either use an existing key ARN or create a new one)
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS encryption"
  policy                  = "{"version":"2012-10-17","statement":[{"Sid":"Allow access for KMS key","Effect":"Allow","Principal":{"AWS":"arn:aws:iam::${data.aws_caller_identity.current.account_id}:user/terraform"},"Action":["kms:Encrypt","kms:Decrypt","kms:ReEncrypt*","kms:GenerateDataKey*","kms:DescribeKey"],"Resource":"*"}]}"
}

data "aws_caller_identity" "current" {}

# Security Group
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow access to PostgreSQL database"
  vpc_id      = data.aws_vpc.selected.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict this to your application servers' IP ranges.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# DB Parameter Group
resource "aws_db_parameter_group" "default" {
  name        = "my-postgresql-parameter-group"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL 15"

  parameter {
    name  = "shared_buffers"
    value = "128MB"
  }
}

# RDS Instance
resource "aws_db_instance" "default" {
  allocated_storage    = 50
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.medium" # Adjust as needed
  name                 = "my-postgresql-instance"
  username             = "admin" # Change this!
  password             = "your_password" # Change this!  Use a secret manager in production.
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  multi_az             = true
  kms_key_id           = aws_kms_key.rds_key.arn
  db_parameter_group_name = aws_db_parameter_group.default.name
  skip_final_snapshot  = true

  tags = {
    Name = "my-postgresql-instance"
  }
}

# Outputs
output "rds_endpoint" {
