response:
Okay, let's break down this request into Terraform components and then assemble the HCL code.

1.  **VPC:** We'll need an existing VPC. The example assumes it exists and takes the ID as an input.
2.  **Subnet Group:** Create a DB subnet group referencing two private subnets within the designated VPC. I'll need the subnet IDs as inputs.
3.  **Security Group:** Create a security group allowing inbound PostgreSQL traffic from a specified source (CIDR block).  I'll use 0.0.0.0/0 for testing, but this should be restricted in a real-world scenario.
4.  **KMS Key:** Create a KMS key to encrypt the RDS instance.
5.  **Parameter Group:** Create a custom PostgreSQL parameter group.
6.  **RDS Instance:**  Create the RDS instance itself, referencing all created components. This includes specifying the engine version, instance class, storage, Multi-AZ, and other requested parameters.

Here’s the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

# Variables
variable "vpc_id" {
  type        = string
  description = "The ID of the VPC"
}

variable "subnet_ids" {
  type        = list(string)
  description = "A list of subnet IDs within the VPC"
}

variable "source_cidr" {
  type        = string
  description = "CIDR block to allow inbound PostgreSQL traffic"
  default     = "0.0.0.0/0" # Restricted to secure CIDR in production
}

# KMS Key for encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS encryption"
  key_usage               = "ENCRYPT_DECRYPT"
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "my-db-subnet-group"
  subnet_ids = var.subnet_ids
}

# Custom DB Parameter Group
resource "aws_db_parameter_group" "default" {
  name   = "my-custom-pg-param-group"
  family = "postgres14" # Specify proper PG version
}

# Security Group
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow PostgreSQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [var.source_cidr]
  }
}

# RDS Instance
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "14.9"  # Specify desired PostgreSQL version
  instance_class       = "db.t3.micro"
  name                 = "my-protected-postgres"
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  multi_az             = true
  backup_retention_period = 7
  skip_final_snapshot = true

  parameter_group_name = aws_db_parameter_group.default.name
  kms_key_id           = aws_kms_key.rds_key.arn

}
