  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Airbyte Test DB Security Group"
  }
}

resource "aws_db_instance" "default" {
  allocated_storage    = 500
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.m6g.large"
  name                 = "airbyte-test-db"
  username             = var.db_username
  password             = var.db_password
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.allow_postgres.id]
  publicly_accessible  = true
  skip_final_snapshot  = true #For test environments.  Remove for production.
  identifier           = "airbyte-test-db" # Required, must be unique
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 500
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
 Okay, let's break down the requirements and then generate the Terraform configuration.

1. **RDS Instance:** We need an `aws_db_instance` resource.
2. **Engine:** The engine must be `postgresql` and the version should be `15`.
3. **Instance Class:** Choose a suitable instance class. For test workloads and 500GB storage, 'db.m6g.large' looks reasonable.  We'll use this and can adjust it later.
4. **Storage:**  500 GB of storage is specified. We'll set `allocated_storage` to 500.
5. **Publicly Accessible:** The database needs to be accessible from public networks for testing Airbyte connectors. Set `publicly_accessible = true`. Security should be handled through Security Groups.
6. **Subnet Group:** We need an `aws_db_subnet_group` to define the subnets the database instance will operate in.  This should specify the public subnets.  Because we don't have specific subnet IDs, I'll use variables for those so that the user can fill in their subnet IDs.
7. **Security Groups:** A `aws_security_group` is necessary to allow inbound connections. We will allow PostgreSQL traffic (port 5432) from anywhere (0.0.0.0/0). While this is OK for a test environment, security best practices *strongly* recommend restricting this to specifically known IP addresses in a production environment.
8. **VPC:** The DB subnet group requires a VPC. I will use a variable for this as well.
9. **DB Name, Username, Password:** Specify the DB name, username and password for the database. I will use variables as these are sensitive.
10. **Tags:** Add a descriptive name tag.

Here's the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "vpc_id" {
  type        = string
  description = "The ID of the VPC in which to create the DB subnet group."
}

variable "public_subnet_ids" {
  type        = list(string)
  description = "A list of public subnet IDs where the DB instance will be created."
}

variable "db_name" {
  type        = string
  description = "The name of the database."
  default     = "airbyte_test_db"
}

variable "db_username" {
  type        = string
  description = "The username for the database."
  sensitive   = true
}

variable "db_password" {
  type        = string
  description = "The password for the database."
  sensitive   = true
}


resource "aws_db_subnet_group" "default" {
  name        = "airbyte-test-db-subnet-group"
  subnet_ids = var.public_subnet_ids
  vpc_id      = var.vpc_id

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

resource "aws_security_group" "allow_postgres" {
  name        = "allow_postgres"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Airbyte Test DB Security Group"
  }
}

resource "aws_db_instance" "default" {
  allocated_storage    = 500
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.m6g.large"
  name                 = "airbyte-test-db"
  username             = var.db_username
  password             = var.db_password
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.allow_postgres.id]
  publicly_accessible  = true
  skip_final_snapshot  = true #For test environments.  Remove for production.
  identifier           = "airbyte-test-db" # Required, must be unique
}
```

