terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# 1. VPC and Subnets
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "aurora-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "aurora-private-subnet-2"
  }
}

# 2. Security Groups
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-sg"
  description = "Security group for Aurora MySQL"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.rds_proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"] #Consider restricting this to only necessary CIDR blocks
  }
}

resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] #Restrict this to your application's CIDR block
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. IAM Role (for Aurora)
resource "aws_iam_role" "aurora_role" {
  name               = "aurora-secretsmanager-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_policy" "aurora_secretsmanager_policy" {
  name        = "aurora-secretsmanager-policy"
  description = "Policy for Aurora to access Secrets Manager"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*" #Consider specifying a specific ARN for the secret
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "aurora_secretsmanager_attachment" {
  role       = aws_iam_role.aurora_role.name
  policy_arn = aws_iam_policy.aurora_secretsmanager_policy.arn
}

# 4. Secrets Manager Secret
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
  tags = {
    Name = "Aurora DB Credentials"
  }
}

# 5. Aurora MySQL Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "serverless"
  engine_version          = "5.7.mysql_aurora.2.11.2" #Choose appropriate version
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = aws_secretsmanager_secret.db_credentials.rotated_secret_arn
  db_subnet_group_name    = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  scaling_configuration {
    min_capacity = 2
    max_capacity = 8
    auto_pause   = true
  }
  skip_final_snapshot = true
}

# 6. RDS Proxy
resource "aws_rds_proxy" "default" {
  proxy_identifier = "aurora-rds-proxy"
  engine_family = "MYSQL"
  db_cluster_identifier = aws_rds_cluster.default.id
  vpc_subnet_ids   = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  auth_iam_role_arn = aws_iam_role.aurora_role.arn
  require_ssl = false
}

# 7. DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name        = "aurora-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
}

