  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "private_subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Replace with your desired AZ
  tags = {
    Name = "aurora-private-subnet-a"
  }
}

resource "aws_subnet" "private_subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Replace with your desired AZ
  tags = {
    Name = "aurora-private-subnet-b"
  }
}

# 2. Security Groups
resource "aws_security_group" "rds_proxy" {
  name        = "rds-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.rds.id]  #Allow traffic from RDS security group
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "rds" {
  name        = "rds-sg"
  description = "Security group for RDS Aurora MySQL"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.rds_proxy.id] #Only allow from RDS proxy.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}


# 3. IAM Role for RDS to access Secrets Manager
resource "aws_iam_role" "rds_secrets_manager" {
  name               = "rds-secretsmanager-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "rds.amazonaws.com"
        },
      },
    ],
  })
}

resource "aws_iam_policy" "rds_secrets_manager_policy" {
  name        = "rds-secretsmanager-policy"
  description = "Policy for RDS to access secrets"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ],
        Effect   = "Allow",
        Resource = "*" # Consider scoping down to specific secret ARN
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "rds_secrets_manager_attachment" {
  role       = aws_iam_role.rds_secrets_manager.name
  policy_arn = aws_iam_policy.rds_secrets_manager_policy.arn
}

# 4. Secrets Manager Secret
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
  tags = {
    Name = "Aurora DB Credentials"
  }
}

# 5. RDS Proxy
resource "aws_rds_proxy" "default" {
  proxy_name            = "aurora-rds-proxy"
  engine_family         = "MYSQL"
  role_arn              = aws_iam_role.rds_secrets_manager.arn
  secret_arn            = aws_secretsmanager_secret.db_credentials.arn
  vpc_subnet_ids        = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
  vpc_security_group_ids = [aws_security_group.rds_proxy.id]
  auth_type             = "PASSWORD"
  require_tls           = true
}

# 6. Aurora Cluster
resource "aws_rds_cluster" "default" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "5.7.mysql_aurora.2.11.2" #set to desired version.
  database_name           = "mydb"
  master_username         = "admin" # Will be overridden by secrets
  master_password_secret_arn = aws_secretsmanager_secret.db_credentials.arn
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  db_subnet_group_name    = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]
}

# 7. DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "aurora-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]
}

# 8. Output
output "aurora_cluster_endpoint" {
  value = aws_rds_cluster.default.endpoint
}
