reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "azs" {
    state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.azs.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_instance" "my_instance" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"     # Replace with your desired instance type
  subnet_id     = module.vpc.public_subnets[0]
}

resource "aws_lb" "test" {
  load_balancer_type = "network"

  subnet_mapping {
    subnet_id     = module.vpc.public_subnet_arns[0]
    allocation_id = aws_eip.example1.id
  }

  subnet_mapping {
    subnet_id     = module.vpc.public_subnet_arns[1]
    allocation_id = aws_eip.example2.id
  }
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_instance.my_instance.id
}

resource "aws_eip" "example1" {

}

resource "aws_eip" "example2" {

}

response:
: Okay, let's break down the requirements and then generate the Terraform configuration.

**1. Resources Needed:**

*   **AWS Elastic IP:** We'll need to allocate Elastic IPs if they don't already exist. The user will *specify* these, so we won't be *allocating* them in this Terraform, only *associating* with the load balancer.
*   **AWS Load Balancer:**  We'll need an Application Load Balancer (ALB).  ALBs are generally preferred for modern applications.
*   **AWS Listener:** An ALB needs at least one listener to accept traffic. We'll configure a listener on port 80 (HTTP) and forward traffic to a target group.
*   **AWS Target Group:** A target group will be created to register backend instances with the load balancer. (Note: We won't *create* the instances; this configuration assumes they exist).
*   **AWS Load Balancer Listener Rule:** We will tie the listener to the target group with a default rule.

**2. User Input:**

The user provides the Elastic IP addresses. We will take these as variables.  Also, let's assume a VPC and subnet IDs as variables for flexibility.  We will also need a security group ID.

**3. Configuration Structure:**

We'll define variables for the required inputs and then define the resources in the correct order of dependencies.

**4. Considerations:**

*   Error handling: This is a basic configuration and doesn't include extensive error handling.
*   Scalability/High Availability:  This assumes backend instances are appropriately scaled and configured for HA; the LB configuration itself contributes to HA.
*   Health Checks:  Target group health checks are critical; we'll add a basic one.
*   Security:  Ensure appropriate security group rules are in place to restrict access to the LB.
*   Naming: We'll use descriptive resource names.

```hcl
variable "name_prefix" {
  type        string
  default     "my-load-balancer"
  description = "Prefix for resource names"
}

variable "vpc_id" {
  type        string
  description = "The ID of the VPC"
}

variable "subnet_ids" {
  type        list(string)
  description = "A list of subnet IDs to attach to the load balancer."
}

variable "security_group_id" {
  type        string
  description = "The ID of the security group to associate with the load balancer."
}

variable "elastic_ip_addresses" {
  type        list(string)
  description = "A list of Elastic IP addresses to associate with the load balancer."
}

variable "target_group_port" {
  type        number
  default     80
  description = "The port on the target instances (e.g. 80, 443)"
}

variable "target_group_protocol" {
  type        string
  default     "HTTP"
  description = "The protocol for the target group (e.g. HTTP, HTTPS)"
}

variable "health_check_path" {
  type        string
  default     "/"
  description = "Path for health checks"
}

resource "aws_lb" "main" {
  name               = "${var.name_prefix}-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [var.security_group_id]
  subnets            = var.subnet_ids

  enable_deletion_protection = false # set to true in production

  tags = {
    Name = "${var.name_prefix}-lb"
  }
}

# Associate Elastic IPs to the load balancer
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.default.arn
  }
}


resource "aws_lb_target_group" "default" {
  name     = "${var.name_prefix}-tg"
  port     = var.target_group_port
  protocol = var.target_group_protocol
  vpc_id   = var.vpc_id

  health_check {
    path     = var.health_check_path
    protocol = "HTTP"
    interval = 30
    timeout  = 5
    healthy_threshold = 2
    unhealthy_threshold = 2
  }
}

# Associate elastic IPs
resource "aws_elastic_ip_association" "eip_assoc" {
  count = length(var.elastic_ip_addresses)
  allocation_id = var.elastic_ip_addresses[count.index]
  network_interface_id = aws_lb.main.network_interface_ids[0]
  depends_on = [aws_lb.main]
}
