    Name = "oidc-subnet-b"
  }
}


resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Security group for the ALB"
  vpc_id      = aws_vpc.main.id
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "main" {
  name               = "oidc-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_subnet_a.id, aws_subnet.public_subnet_b.id]

  enable_deletion_protection = false
}

resource "aws_lb_target_group" "main" {
  name     = "oidc-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
  health_check {
    path     = "/"
    protocol = "HTTP"
  }
}

resource "aws_lb_listener" "main" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "authenticate-oidc"
    authenticate_oidc {
      issuer {
        issuer_uri = "https://your-oidc-provider.com" # Replace with your OIDC provider's issuer URI
      }

      authorization_endpoint = "https://your-oidc-provider.com/authorize" # Replace with your OIDC provider's authorization endpoint
      token_endpoint           = "https://your-oidc-provider.com/token" # Replace with your OIDC provider's token endpoint
      client_id                = "your-client-id" # Replace with your client ID
      client_secret            = "your-client-secret" # Replace with your client secret
      scope                    = "openid email profile" # Replace with the desired scopes
      session_timeout_seconds  = 3600
    }
  }
}

resource "aws_lb_listener_rule" "main" {
  listener_arn = aws_lb_listener.main.arn
  priority     = 1

  condition {
    field  = "path-pattern"
    values = ["/*"]
  }

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

