  protocol          = "HTTP"

  default_action {
    type             = "authenticate-oidc"
    authenticate_oidc {
      issuer {
        issuer_uri = "https://your-oidc-provider.com" # Replace with your OIDC provider's issuer URI
      }

      authorization_endpoint = "https://your-oidc-provider.com/authorize" # Replace with your OIDC provider's authorization endpoint
      token_endpoint           = "https://your-oidc-provider.com/token" # Replace with your OIDC provider's token endpoint
      client_id                = "your-client-id" # Replace with your client ID
      client_secret            = "your-client-secret" # Replace with your client secret
      scope                    = "openid email profile" # Replace with the desired scopes
      session_timeout_seconds  = 3600
    }
  }
}

resource "aws_lb_listener_rule" "main" {
  listener_arn = aws_lb_listener.main.arn
  priority     = 1

  condition {
    field  = "path-pattern"
    values = ["/*"]
  }

