  secret_id     = aws_secretsmanager_secret.db_credentials.id
  version_stage = "AWSCURRENT"

  secret_string = jsonencode({
    username = "admin"
    password = "supersecretpassword" # Replace with a strong password
  })
}

# 3. RDS Instance (Example: PostgreSQL)
