: Okay, let's break this down. The request asks for an Amazon EFS file system with a resource-based policy. Here's how we'll approach it:

1.  **EFS File System:** We'll use the `aws_efs_file_system` resource to create the EFS volume.

2.  **Resource-Based Policy:** We will use the `aws_efs_access_point` resource and specify an access policy for it. This effectively acts as a resource-based policy for the EFS file system. We'll craft a simple example policy allowing read-only access to a specific AWS account.  This policy can be tailored based on your specific security needs.

Here's the Terraform configuration:

```hcl
resource "aws_efs_file_system" "example" {
  creation_token = "example-efs"
  tags = {
    Name = "example-efs"
  }
}

resource "aws_efs_access_point" "example" {
  file_system_id = aws_efs_file_system.example.id
  posix_user {
    uid      = 1000
    gid      = 1000
    secondary_gids = []
  }

  root_directory {
    path = "/efs"
    creation_info {
      owner_gid = 1000
      owner_uid = 1000
      permissions = "755"
    }
  }

  access_policy = jsonencode({
    "Version" : "2012-10-17",
    "Statement" : [
      {
        "Sid" : "AllowAccess",
        "Effect" : "Allow",
        "Principal" : {
          "AWS" : "arn:aws:iam::123456789012:root" # Replace with the target account ID
        },
        "Action" : "elasticfilesystem:ClientMount",
        "Resource" : aws_efs_file_system.example.arn
      },
      {
        "Sid": "ReadOnlyAccess",
        "Effect": "Allow",
        "Principal": {
          "AWS": "arn:aws:iam::123456789012:root"  # Replace with the target account ID
        },
        "Action": [
          "elasticfilesystem:DescribeMountTargets",
          "elasticfilesystem:DescribeFileSystems",
          "elasticfilesystem:ClientRootAccess"
        ],
        "Resource": aws_efs_file_system.example.arn
      }
    ]
  })
}
```

