  environment_name = "eb_env_1"
  solution_stack_name = "64bit Amazon Linux 2 v3.5.2 running Node.js 18" # Adjust stack as needed
  vpc_id          = aws_vpc.eb_vpc.id
  subnet_ids      = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
  security_group_ids = [aws_security_group.eb_env_sg.id]
}

resource "aws_elasticbeanstalk_environment" "eb_env_2" {
  application_name = "your_eb_app_name" # Replace with your EB app name
  environment_name = "eb_env_2"
  solution_stack_name = "64bit Amazon Linux 2 v3.5.2 running Node.js 18" # Adjust stack as needed
