reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

variable "cluster_name" {
  type = string
  default = "test-cluster"
}

data "aws_region" "current" {}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "test_eks_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "test_eks_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  availability_zone = data.aws_availability_zones.available.names[1]
}

resource "aws_iam_role" "example" {
  name = "${var.cluster_name}-eks"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.example.name
}

resource "aws_eks_cluster" "example" {
  name     = var.cluster_name
  role_arn = aws_iam_role.example.arn

  vpc_config {
    subnet_ids = [ aws_subnet.test_eks_1.id, aws_subnet.test_eks_2.id ]
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete EKS managed EC2 infrastructure such as Security Groups.
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # Manage kubectl configuration
  provisioner "local-exec" {
    command = "aws eks --region ${data.aws_region.current.name} update-kubeconfig --name ${self.name}"
  }

  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset users.${self.arn}"
  }
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset clusters.${self.arn}"
  }
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config unset contexts.${self.arn}"
  }
}

response:
Okay, let's break this down into manageable steps and then construct the Terraform configuration.

1.  **Provider Configuration:** We'll start with the AWS provider, specifying the region.
2.  **Caller Identity:** We'll use `aws_caller_identity` to get information about the current AWS account and user.
3.  **Locals:** Define locals for the workspace, tags and image tag.
4.  **ECR Image Lookup:** We will use a `data` block to look up the most recent stable ECR image tag.
5.  **EKS Module:** We'll utilize an EKS module (I will use a standard one, and you might want to customize it with your preferred module). This will handle cluster creation, IAM roles, node groups, etc.
6.  **EKS Cluster Metadata:** Extract the cluster endpoint, certificate authority, and other important details using `${eks_cluster.example.kubeconfig}`.
7.  **Kubernetes & Helm Providers:** Configure the Kubernetes and Helm providers using the information obtained from the EKS cluster module.

Here's the Terraform HCL code implementing all these steps:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired AWS region
}

data "aws_caller_identity" "current" {}

locals {
  workspace = "my-eks-cluster"
  tags = {
    Environment = "dev"
    Terraform   = "true"
  }
  ecr_image_tag = "latest" # Assuming 'latest' will get the most recent.  Consider using a more specific filter
}

data "aws_ecr_image" "stable_image" {
  repository_name = "your-ecr-repository-name" # Replace with your ECR repository name
  image_tag       = local.ecr_image_tag
}


resource "aws_eks_cluster" "example" {
  name     = local.workspace
  role_arn = aws_iam_role.eks_cluster.arn
  version  = "1.28"

  vpc_config {
    subnet_ids = [
      "subnet-xxxxxxxxxxxxxxxxx",  # Replace with your subnet IDs
      "subnet-yyyyyyyyyyyyyyyyy",
    ]
  }

  tags = local.tags
}

resource "aws_iam_role" "eks_cluster" {
  name = "${local.workspace}-eks-cluster-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "eks.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  role       = aws_iam_role.eks_cluster.name
  policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess" # Replace with a more restrictive policy!
}


resource "kubernetes_provider" "eks" {
  host                   = aws_eks_cluster.example.endpoint
  cluster_ca_certificate = base64decode(aws_eks_cluster.example.certificate_authority.data)
  token                  = data.aws_eks_cluster_auth_info.example.token
}

data "aws_eks_cluster_auth_info" "example" {
  cluster_name = aws_eks_cluster.example.name
}

resource "helm_provider" "eks" {
  kubernetes {
    host                   = aws_eks_cluster.example.endpoint
    cluster_ca_certificate = base64decode(aws_eks_cluster.example.certificate_authority.data)
    token                  = data.aws_eks_cluster_auth_info.example.token
  }
}

output "caller_identity" {
  value = data.aws_caller_identity.current
}

output "eks_cluster_name" {
  value = aws_eks_cluster.example.name
}

output "eks_cluster_endpoint" {
  value = aws_eks_cluster.example.endpoint
}
