Okay, let's break down this request. We need to create two S3 buckets:

1.  **Source Bucket:** This is the main bucket where objects will be stored.
2.  **Destination Bucket:** This bucket will store the server access logs generated by the source bucket.

We also need to configure the source bucket to deliver its access logs to the destination bucket. This involves setting up an S3 bucket logging configuration.

Here's the Terraform configuration to achieve this. It will include resource declarations for both buckets and the logging configuration. We will parameterize bucket names for re-usability.

```hcl
resource "aws_s3_bucket" "source_bucket" {
  bucket = var.source_bucket_name
  acl    = "private"

  versioning {
    enabled = true
  }

  tags = {
    Name        = "Source S3 Bucket"
    Environment = "Development"
  }
}

resource "aws_s3_bucket" "destination_bucket" {
  bucket = var.destination_bucket_name
  acl    = "private"

  tags = {
    Name        = "Destination S3 Bucket"
    Environment = "Development"
  }
}

resource "aws_s3_bucket_logging" "source_bucket_logging" {
  bucket = aws_s3_bucket.source_bucket.id
  target_bucket = aws_s3_bucket.destination_bucket.id
  target_prefix = "access-logs/"
}

variable "source_bucket_name" {
  type        = string
  description = "The name of the source S3 bucket"
  default     = "my-source-s3-bucket-unique-name"
}

variable "destination_bucket_name" {
  type        = string
  description = "The name of the destination S3 bucket"
  default     = "my-destination-s3-bucket-unique-name"
}
