Okay, let's break this down. We need to:

1.  **Create a Backup Vault:** AWS Backup vaults are containers for backups. We'll need to define a vault.
2.  **Create a Backup Plan:**  A Backup Plan defines the backup schedule (daily at 12:00 AM). We'll attach this to the vault.
3.  **Create a Backup Selection:** This specifies *what* to back up. In our case, it will target an EC2 instance.  We'll use tags to select the instance.
4.  **EC2 Instance:** We'll create a simple EC2 Instance to be backed up.

Here's the Terraform configuration to achieve this:

```hcl
resource "aws_ec2_instance" "example" {
  ami           = "ami-0c55bca456d72561a" # Replace with a suitable AMI ID for your region
  instance_type = "t2.micro"
  tags = {
    Name        = "Terraform Backup Test Instance"
    BackupTarget = "true"
  }
}

resource "aws_backup_vault" "example" {
  name = "terraform-backup-vault"
}

resource "aws_backup_plan" "example" {
  name = "daily-backup-plan"
  rule {
    rule_name = "DailyBackupRule"
    target_object_type = "EC2"
    schedule {
      cron_expression = "0 0 * * ?" # Daily at 12:00 AM
    }
    lifecycle {
      delete_after = "7" # keep backups for 7 days
    }
  }
}

resource "aws_backup_selection" "example" {
  backup_plan_id = aws_backup_plan.example.id
  resource_arn   = aws_ec2_instance.example.arn
  tags = {
    BackupTarget = "true"
  }

}
```

