  instance_type = "t2.micro"
  key_name      = "your_key_pair"  # Replace with your key pair name

  tags = {
    Name = "Terraform-EC2-Instance"
  }
}

# Security Group for SSH access
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-sg"
  description = "Allow SSH inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Open to the world.  Restrict to your IP in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "example_with_sg" {
  ami           = "ami-0c55b75028e6b2158" # Replace with a suitable AMI for your region
  instance_type = "t2.micro"
