data "aws_vpc" "default" {
  default = true
}

# 2. AWS Backup Vault
resource "aws_backup_vault" "example" {
  name = "terraform-backup-vault"

  tags = {
    Name = "TerraformBackupVault"
  }
}

# 3. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "AWSBackupServiceRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "backup.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })

  tags = {
    Name = "BackupServiceRole"
  }
}

# 4. AWS Backup Plan
resource "aws_backup_plan" "example" {
  name = "daily-ec2-backup-plan"
  rule {
    rule_name = "DailyBackupRule"
    target_resource_type = "EC2"
    schedule {
      cron_expression = "0 0 * * ?" # Daily at 12:00 AM
    }
    lifecycle {
      delete_after = "7" # Retention period of 7 days
    }
  }
}

# 5. AWS Backup Selection
resource "aws_backup_selection" "example" {
  backup_plan_id = aws_backup_plan.example.id
  vault_name     = aws_backup_vault.example.name
  resource_selection {
    resources = [
      "arn:aws:ec2:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:instance/${aws_instance.example_with_sg.id}"
    ]
  }

  tags = {
    Name = "EC2BackupSelection"
  }
}

