  type        = string
  description = "The AWS region to deploy to."
  default     = "us-east-1" # Adjust the region as needed
}

# Create an S3 bucket
resource "aws_s3_bucket" "video_bucket" {
  bucket = var.bucket_name != "" ? var.bucket_name : "video-streaming-bucket-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  tags = {
    Name        = "Video Streaming Bucket"
    Environment = "Production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Create a CloudFront Origin Access Identity (OAI)
resource "aws_cloudfront_access_key" "cloudfront_oai" {
  name          = "cloudfront-oai-key"
  comment       = "Origin Access Identity for S3 bucket"
}

# Bucket Policy to allow CloudFront OAI access
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "s3:GetObject",
        Effect   = "Allow",
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_access_key.cloudfront_oai.id}"
        },
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}

# Create a CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  domain_name              = var.domain_name
  comment                  = "CloudFront distribution for video streaming"
  enabled                  = true

  origin {
    domain_name           = aws_s3_bucket.video_bucket.bucket_website_endpoint
    origin_id             = "S3Origin"
    custom_origin_config {
      http_port = 80
      https_port = 443
      origin_protocol_policy = "http-only" # Secure with HTTPS in production if supported by S3.
      origin_ssl_protocols = ["TLSv1.2"]
    }
  }

  default_cache_behavior {
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https" # Enforce HTTPS
    allowed_methods = ["GET", "HEAD"]
    cached_methods = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies = {
        forward = "none"
      }
    }
  }

  viewer_certificate {
    acm_certificate_arn = var.certificate_arn
    ssl_support_method = "sni-only"
  }

  restrictions {
    geo_restriction {
      restriction_type = "none" # Adjust as needed
    }
  }

  logging_config {
    log_bucket = aws_s3_bucket.video_bucket.bucket
    include_cookies = false
    prefix = "cloudfront-logs/"
  }

  tags = {
    Name        = "Video Streaming Distribution"
    Environment = "Production"
  }

  default_root_object = "index.html" # Or other default file
}

# Create a Route 53 hosted zone (if one doesn't exist)
# In a real-world scenario, you might want to use an existing zone.
# resource "aws_route53_zone" "hosted_zone" {
#   name = var.domain_name
# }


# Create a Route 53 record to point to the CloudFront distribution
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.hosted_zone.zone_id # Replace with your existing zone ID
  name    = var.domain_name
  type    = "A"
  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
  ttl     = 300  # seconds
}

