terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "video_content" {
  bucket_prefix = "video-content-"
}

resource "aws_s3_object" "put_website" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "index.html"
  source = "./supplement/index.html"
  content_type = "text/html"
}

resource "aws_s3_object" "put_website_css" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "css/style.css"
  source = "./supplement/css/style.css"
  content_type = "text/css"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.my_distribution.arn
          }
        }
      }
    ]
  })
}


locals {
  s3_origin_id = "s3_video_content_origin"
}

resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "s3-oac"
  description                       = "aws access control policy"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "my_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = local.s3_origin_id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
  }

  price_class = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Route53
resource "aws_route53_zone" "my_zone" {
  name = "my-test-cloudfront.com"
}

resource "aws_route53_record" "cdn_ipv4" {
  type    = "A"
  name    = "cdn"
  zone_id = aws_route53_zone.my_zone.zone_id

  alias {
    name                   = aws_cloudfront_distribution.my_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.my_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

response:
Okay, let's break down the requirements and design a Terraform configuration for a globally distributed video streaming platform on AWS.

**1. Core Components:**

*   **S3:**  We'll use S3 to store the video files.  We'll enable static website hosting and versioning.  Consider bucket encryption for security.
*   **CloudFront:**  This will be our CDN, caching the video content at edge locations globally.  We'll configure it to pull content from the S3 bucket.  We'll need Origin Access Identity (OAI) to restrict direct S3 access.
*   **Route 53:** We'll use Route 53 to manage DNS records for our platform, pointing to the CloudFront distribution.  We'll use an Alias record type.
*   **ACM (AWS Certificate Manager):**  We'll need an SSL/TLS certificate for secure HTTPS delivery via CloudFront.

**2. Additional Considerations:**

*   **Origin Access Identity (OAI):**  Essential for securing S3 content.
*   **CloudFront Behaviors:** A default behavior to route all requests to the index document (e.g., a player page).
*   **Error Pages:** Configure custom error pages in CloudFront (e.g. 403, 404).
*   **Logging:** Enable CloudFront logging to S3 for monitoring and troubleshooting.
*   **Tags:** Add tags to resources for cost allocation and management.
*   **Versioning:** Enable versioning on the S3 bucket to prevent accidental data loss.

**3. Terraform Resources:**

*   `aws_s3_bucket`:  The S3 bucket to store video files.
*   `aws_s3_bucket_versioning`: To enable versioning of files in the S3 bucket.
*   `aws_cloudfront_access_key`: Creates an Origin Access Identity (OAI).
*   `aws_cloudfront_distribution`: The CloudFront distribution configuration.
*   `aws_route53_zone`: The Route 53 hosted zone for our domain.
*   `aws_route53_record`: The Route 53 record pointing our domain to the CloudFront distribution.
*   `aws_acm_certificate`:  The SSL/TLS certificate.
*   `aws_s3_bucket_policy`: Bucket policy to allow CloudFront OAI access to S3.

**4. Variables:**

*   `domain_name`: The domain name for the video platform.
*   `bucket_name`: A unique name for the S3 bucket.  Terraform will generate a unique name if not provided.
*   `certificate_arn`: ARN of the SSL/TLS certificate in ACM.
*   `aws_region`: AWS region to deploy to.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "domain_name" {
  type        = string
  description = "The domain name for the video platform."
}

variable "bucket_name" {
  type        = string
  description = "The name of the S3 bucket. If not provided, Terraform will generate a unique name."
  default     = ""
}

variable "certificate_arn" {
  type        = string
  description = "The ARN of the SSL/TLS certificate in ACM."
}

variable "aws_region" {
  type        = string
  description = "The AWS region to deploy to."
  default     = "us-east-1" # Adjust the region as needed
}

# Create an S3 bucket
resource "aws_s3_bucket" "video_bucket" {
  bucket = var.bucket_name != "" ? var.bucket_name : "video-streaming-bucket-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  tags = {
    Name        = "Video Streaming Bucket"
    Environment = "Production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Create a CloudFront Origin Access Identity (OAI)
resource "aws_cloudfront_access_key" "cloudfront_oai" {
  name          = "cloudfront-oai-key"
  comment       = "Origin Access Identity for S3 bucket"
}

# Bucket Policy to allow CloudFront OAI access
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "s3:GetObject",
        Effect   = "Allow",
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_access_key.cloudfront_oai.id}"
        },
        Resource = "arn:aws:s3:::${aws_s3_bucket.video_bucket.bucket}/*"
      }
    ]
  })
}

# Create a CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  domain_name              = var.domain_name
  comment                  = "CloudFront distribution for video streaming"
  enabled                  = true

  origin {
    domain_name           = aws_s3_bucket.video_bucket.bucket_website_endpoint
    origin_id             = "S3Origin"
    custom_origin_config {
      http_port = 80
      https_port = 443
      origin_protocol_policy = "http-only" # Secure with HTTPS in production if supported by S3.
      origin_ssl_protocols = ["TLSv1.2"]
    }
  }

  default_cache_behavior {
    target_origin_id = "S3Origin"
    viewer_protocol_policy = "redirect-to-https" # Enforce HTTPS
    allowed_methods = ["GET", "HEAD"]
    cached_methods = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies = {
        forward = "none"
      }
    }
  }

  viewer_certificate {
    acm_certificate_arn = var.certificate_arn
    ssl_support_method = "sni-only"
  }

  restrictions {
    geo_restriction {
      restriction_type = "none" # Adjust as needed
    }
  }

  logging_config {
    log_bucket = aws_s3_bucket.video_bucket.bucket
    include_cookies = false
    prefix = "cloudfront-logs/"
  }

  tags = {
    Name        = "Video Streaming Distribution"
    Environment = "Production"
  }

  default_root_object = "index.html" # Or other default file
}

# Create a Route 53 hosted zone (if one doesn't exist)
# In a real-world scenario, you might want to use an existing zone.
# resource "aws_route53_zone" "hosted_zone" {
#   name = var.domain_name
# }


# Create a Route 53 record to point to the CloudFront distribution
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.hosted_zone.zone_id # Replace with your existing zone ID
  name    = var.domain_name
  type    = "A"
  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
  ttl     = 300  # seconds
}
